insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('machine-chest-press', 'Machine Chest Press', ARRAY['chest']::text[], ARRAY['triceps', 'shoulders']::text[], 'horizontal_push', ARRAY['chest_press_machine']::text[], true, false, 'machine_stack', 'Adjust the seat height so the handles sit level with mid-chest. Sit back fully against the pad, feet flat on the floor.', 'Press the handles forward until arms are extended but elbows are not locked out hard, then return under control to the starting position without letting the stack slam.', 'Exhale as you press forward, inhale as you return the handles toward your chest.', ARRAY['Flaring elbows to 90 degrees and stressing the front of the shoulder', 'Letting the weight stack crash down between reps', 'Arching the lower back off the pad to force out extra reps']::text[], 'low', 'machine_handle', 'Both handles move together on a fixed machine stack; there is no independent per-hand load.', 'The neutral machine handles keep the wrist in a fixed, supported position, so this is one of the safest chest presses for the plated right forearm — no free-weight grip stabilisation is required.', '{}', null, 8, 12, 'Add one stack increment once all sets hit the top of the rep range with 1-2 reps in reserve.', ARRAY['incline-dumbbell-press', 'flat-dumbbell-press']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('incline-dumbbell-press', 'Incline Dumbbell Press', ARRAY['chest']::text[], ARRAY['shoulders', 'triceps']::text[], 'horizontal_push', ARRAY['dumbbell', 'bench']::text[], true, false, 'per_hand', 'Set the bench to a 30-45 degree incline. Sit with a dumbbell resting upright on each thigh, then kick them up to shoulder height one at a time as you lie back.', 'Press both dumbbells up and slightly inward until arms are extended above the upper chest, then lower with control until the elbows are roughly level with the bench.', 'Inhale on the way down, exhale forcefully as you press up.', ARRAY['Letting the dumbbells drift too far back and stressing the front shoulder', 'Bouncing the weights out of the bottom position', 'Using an incline steeper than 45 degrees, which turns it into a shoulder press']::text[], 'moderate', 'neutral', 'Each dumbbell is loaded and tracked independently; both hands are capped at the same weight for symmetry.', 'Keep wrists stacked directly over the elbows in a neutral-leaning grip rather than letting them cock backward under load, and never exceed 25kg per hand given the titanium plate in the right forearm.', ARRAY['Do not exceed 25kg per dumbbell', 'Avoid if right wrist/forearm is swollen or painful that day']::text[], 25, 8, 12, 'Increase both dumbbells by the smallest available increment once 12 reps are achieved for all sets, up to the 25kg per-hand cap.', ARRAY['machine-chest-press', 'flat-dumbbell-press']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('flat-dumbbell-press', 'Flat Dumbbell Press', ARRAY['chest']::text[], ARRAY['triceps', 'shoulders']::text[], 'horizontal_push', ARRAY['dumbbell', 'bench']::text[], true, false, 'per_hand', 'Lie back on a flat bench with a dumbbell in each hand resting on your thighs, then drive them up to shoulder width using your knees to help the first rep.', 'Press both dumbbells straight up over the chest until arms are extended, then lower under control until the upper arms are roughly parallel with the floor.', 'Inhale as the dumbbells descend, exhale as you press them back up.', ARRAY['Letting the elbows flare past a 45-60 degree angle and loading the shoulder joint', 'Dropping the dumbbells too fast at the bottom', 'Uneven pressing speed between the left and right arm']::text[], 'moderate', 'neutral', 'Each dumbbell is loaded independently; both hands are capped equally so the right hand is never overloaded.', 'Keep the wrist neutral and stacked under the dumbbell rather than letting it bend backward; cap at 25kg per hand for the titanium-plated right forearm.', ARRAY['Do not exceed 25kg per dumbbell', 'Stop if there is any sharp pain in the right forearm']::text[], 25, 8, 12, 'Add the smallest available dumbbell increment once all sets reach 12 reps with good form.', ARRAY['machine-chest-press', 'incline-dumbbell-press']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('dumbbell-chest-fly', 'Flat Dumbbell Chest Fly', ARRAY['chest']::text[], ARRAY['shoulders']::text[], 'horizontal_push', ARRAY['dumbbell', 'bench']::text[], false, false, 'per_hand', 'Lie on a flat bench holding a light dumbbell in each hand above the chest, palms facing each other, elbows slightly bent.', 'Lower the dumbbells out to the sides in a wide arc until you feel a stretch across the chest, then bring them back together over the chest using the chest muscles, not momentum.', 'Inhale as the arms open out to the sides, exhale as you bring them back together.', ARRAY['Bending and straightening the elbows like a press instead of keeping a fixed elbow angle', 'Going too heavy and losing control of the stretch position', 'Letting the wrists roll backward under load at the bottom of the movement']::text[], 'moderate', 'neutral', 'Each dumbbell is loaded independently; keep both hands light and equal, well under the 25kg cap for this isolation move.', 'Use a genuinely light weight for this exercise — the wide-arm stretch position increases leverage on the wrist and forearm, so keep dumbbells modest given the titanium plate.', ARRAY['Do not exceed 25kg per dumbbell', 'Avoid a deep stretch if the shoulder or forearm feels unstable']::text[], 25, 10, 15, 'Add the smallest available dumbbell increment only once 15 controlled reps are achieved with a full, pain-free stretch.', ARRAY['machine-chest-press', 'incline-dumbbell-press']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('pushup', 'Push-Up', ARRAY['chest']::text[], ARRAY['triceps', 'shoulders', 'core']::text[], 'horizontal_push', ARRAY['bodyweight']::text[], true, false, 'bodyweight', 'Place hands slightly wider than shoulder width on the floor, body in a straight line from head to heels.', 'Lower the chest toward the floor by bending the elbows, then press back up to full arm extension.', 'Inhale on the way down, exhale as you press up.', ARRAY['Letting the hips sag or pike up instead of a straight body line', 'Flaring elbows straight out to the sides', 'Not controlling the descent, dropping weight onto the wrists']::text[], 'high', 'none', 'Bodyweight is distributed across both hands, but the wrist is fully weight-bearing and extended, which is exactly the loading pattern to avoid.', 'Push-ups put the wrist in a weight-bearing, extended position under load and are NOT recommended while the right forearm has a titanium plate — use the machine chest press instead.', ARRAY['Not selectable by default due to direct weight-bearing wrist extension', 'Avoid entirely until cleared by a physician for loaded wrist extension']::text[], null, 8, 20, 'Not applicable while contraindicated; if medically cleared, progress by adding reps before elevating feet.', ARRAY['machine-chest-press', 'flat-dumbbell-press']::text[], null, false) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('lat-pulldown', 'Lat Pulldown', ARRAY['lats', 'back']::text[], ARRAY['biceps', 'shoulders']::text[], 'vertical_pull', ARRAY['lat_pulldown_machine']::text[], true, false, 'machine_stack', 'Sit down and secure the thigh pad snugly over your legs. Grip the bar just outside shoulder width with a neutral-leaning or pronated grip.', 'Pull the bar down to the upper chest by driving the elbows down and back, squeezing the shoulder blades together, then let the bar rise under control to full arm extension.', 'Exhale as you pull the bar down, inhale as you let it return up.', ARRAY['Leaning back excessively and turning it into a rowing motion', 'Pulling the bar behind the neck', 'Using momentum/jerking instead of a controlled pull']::text[], 'low', 'machine_handle', 'Both hands share one bar on a fixed cable/stack; load is not split independently per hand.', 'The wide bar grip keeps the wrist in a neutral, supported position throughout — a good lat/back builder that avoids loading the injured forearm directly.', '{}', null, 8, 12, 'Add one stack increment once every set reaches the top of the rep range with 1-2 reps in reserve.', ARRAY['seated-cable-row', 'single-arm-dumbbell-row']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('close-grip-lat-pulldown', 'Close-Grip Lat Pulldown', ARRAY['lats', 'back']::text[], ARRAY['biceps']::text[], 'vertical_pull', ARRAY['lat_pulldown_machine']::text[], true, false, 'machine_stack', 'Attach the close, neutral-grip V-handle to the pulldown cable. Sit with thighs secured under the pad.', 'Pull the handle straight down to the upper chest, keeping elbows close to the body, then return under control to full extension.', 'Exhale pulling down, inhale on the controlled return.', ARRAY['Using body English/leaning back sharply to move the weight', 'Shrugging the shoulders up instead of depressing the shoulder blades', 'Not achieving a full stretch at the top']::text[], 'low', 'neutral', 'Both hands share one neutral V-handle on the machine stack; no independent per-hand loading.', 'The neutral V-handle keeps wrists in the safest possible position for the plated forearm while still training the lats hard.', '{}', null, 8, 12, 'Add one stack increment when all sets reach 12 reps with good scapular control.', ARRAY['lat-pulldown', 'seated-cable-row']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('seated-cable-row', 'Seated Cable Row', ARRAY['back']::text[], ARRAY['lats', 'biceps', 'shoulders']::text[], 'horizontal_pull', ARRAY['seated_row_machine']::text[], true, false, 'machine_stack', 'Sit with feet on the platform, knees slightly bent, and grasp the neutral handle with a straight back and shoulders relaxed.', 'Pull the handle toward the lower abdomen by driving the elbows back and squeezing the shoulder blades together, then extend the arms forward under control without rounding the back.', 'Exhale as you row the handle in, inhale as you extend back out.', ARRAY['Rounding the lower back at full stretch', 'Using momentum by rocking the torso instead of a controlled pull', 'Shrugging the traps up instead of pulling with the mid-back']::text[], 'low', 'neutral', 'Both hands share the machine handle; load comes from a fixed stack, not split per hand.', 'The neutral handle and supported seated position make this one of the safest back builders for the injured right forearm — no independent grip stabilisation required.', '{}', null, 8, 12, 'Add one stack increment once all sets hit 12 reps with a full, controlled range of motion.', ARRAY['lat-pulldown', 'single-arm-dumbbell-row']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('single-arm-dumbbell-row', 'Single-Arm Dumbbell Row', ARRAY['back']::text[], ARRAY['lats', 'biceps', 'shoulders']::text[], 'horizontal_pull', ARRAY['dumbbell', 'bench']::text[], true, true, 'per_hand', 'Place your left knee and left hand on a bench for support, right foot on the floor, back flat and roughly parallel to the ground, dumbbell hanging in the right hand.', 'Row the dumbbell up toward the hip by driving the elbow back, squeezing the shoulder blade, then lower under control to a full stretch. Complete all reps, then switch sides.', 'Exhale as you row the dumbbell up, inhale as you lower it back down.', ARRAY['Twisting the torso to help lift the weight instead of pulling with the back', 'Letting the working shoulder round forward at the bottom', 'Using a weight so heavy that the wrist has to fight to keep the dumbbell stable']::text[], 'moderate', 'neutral', 'Only one hand is loaded at a time; the right hand is capped at 25kg regardless of what the left hand uses.', 'Keep the wrist neutral and let the elbow — not the wrist — do the work of stabilising the dumbbell; hard cap the right hand at 25kg because of the titanium plate.', ARRAY['Right-hand load must not exceed 25kg', 'Stop if the forearm cramps or aches under load']::text[], 25, 8, 12, 'Add the smallest available dumbbell increment once both sides complete 12 controlled reps, up to the 25kg cap.', ARRAY['seated-cable-row', 'lat-pulldown']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('chest-supported-dumbbell-row', 'Chest-Supported Dumbbell Row', ARRAY['back']::text[], ARRAY['lats', 'biceps', 'shoulders']::text[], 'horizontal_pull', ARRAY['dumbbell', 'bench']::text[], true, false, 'per_hand', 'Set an incline bench to about 30 degrees and lie chest-down on it with a dumbbell in each hand hanging straight down.', 'Row both dumbbells up toward the hips by driving the elbows back, squeezing the shoulder blades together, then lower under control to a full stretch.', 'Exhale as you row up, inhale as you lower down.', ARRAY['Lifting the chest off the pad to cheat the weight up', 'Using a jerky, momentum-driven pull', 'Letting the wrists bend instead of hanging neutrally under the dumbbells']::text[], 'moderate', 'neutral', 'Each dumbbell is loaded independently; both hands are capped equally at 25kg for the plated right forearm.', 'The chest support removes lower-back strain and lets you focus on a controlled neutral-wrist pull; keep both dumbbells at or under 25kg.', ARRAY['Do not exceed 25kg per dumbbell']::text[], 25, 8, 12, 'Increase both dumbbells by the smallest increment once 12 reps are completed with full control.', ARRAY['seated-cable-row', 'single-arm-dumbbell-row']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('straight-arm-cable-pulldown', 'Straight-Arm Cable Pulldown', ARRAY['lats']::text[], ARRAY['back', 'core']::text[], 'isolation_extension', ARRAY['cable_stack']::text[], false, false, 'machine_stack', 'Attach a straight or rope bar to the high cable pulley. Stand facing the stack, arms extended in front at shoulder height, slight forward hip hinge.', 'Keeping the elbows nearly straight, pull the bar down in an arc until it reaches the thighs, feeling a squeeze in the lats, then let it return under control.', 'Exhale as the bar sweeps down, inhale as it returns to the top.', ARRAY['Bending the elbows and turning it into a pushdown', 'Using the lower back to yank the weight down', 'Rushing the return phase and losing the lat stretch']::text[], 'low', 'cable_handle', 'Both hands share one bar attachment on the cable stack; load is not split per hand.', 'A cable handle with a light, straight-elbow arc keeps wrist involvement minimal, making this safe for the injured forearm.', '{}', null, 10, 15, 'Add one stack increment once all sets reach 15 reps with a strict, elbow-locked arc.', ARRAY['lat-pulldown', 'seated-cable-row']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('shoulder-press-machine', 'Shoulder Press Machine', ARRAY['shoulders']::text[], ARRAY['triceps']::text[], 'vertical_push', ARRAY['shoulder_press_machine']::text[], true, false, 'machine_stack', 'Adjust the seat so the handles start level with the top of the shoulders. Sit back fully against the pad.', 'Press the handles straight overhead until arms are extended without locking the elbows hard, then lower under control back to shoulder height.', 'Exhale as you press up, inhale as you lower back down.', ARRAY['Arching the lower back away from the pad to press more weight', 'Only completing a partial range of motion', 'Letting the handles crash down at the bottom']::text[], 'low', 'machine_handle', 'Both handles move on a single fixed stack; load is not split independently per hand.', 'The fixed vertical path and neutral machine handles avoid the wrist instability of an overhead free-weight press, making this the preferred shoulder press for the plated forearm.', '{}', null, 8, 12, 'Add one stack increment once all sets hit 12 reps with 1-2 reps in reserve.', ARRAY['dumbbell-shoulder-press', 'cable-lateral-raise']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('dumbbell-shoulder-press', 'Seated Dumbbell Shoulder Press', ARRAY['shoulders']::text[], ARRAY['triceps']::text[], 'vertical_push', ARRAY['dumbbell', 'bench']::text[], true, false, 'per_hand', 'Sit on a bench with back support, a dumbbell in each hand at shoulder height, palms facing forward.', 'Press both dumbbells straight overhead until the arms are extended, then lower under control back to shoulder height.', 'Exhale pressing up, inhale lowering down.', ARRAY['Flaring the wrists back under load at the top of the press', 'Arching the lower back to grind out extra reps', 'Letting one arm lead and press unevenly']::text[], 'moderate', 'neutral', 'Each dumbbell is loaded independently; both hands are capped at 25kg for the plated right forearm.', 'Keep the wrist stacked directly under the dumbbell at the top rather than let it cock backward, and never exceed 25kg per hand; prefer the shoulder press machine on higher-fatigue days.', ARRAY['Do not exceed 25kg per dumbbell', 'Avoid if there is any wrist discomfort on overhead lockout']::text[], 25, 8, 12, 'Increase both dumbbells by the smallest increment once 12 reps are hit for all sets, up to the 25kg cap.', ARRAY['shoulder-press-machine']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('cable-lateral-raise', 'Cable Lateral Raise', ARRAY['shoulders']::text[], ARRAY['traps']::text[], 'isolation_extension', ARRAY['cable_stack']::text[], false, true, 'machine_stack', 'Set the pulley to the lowest position and attach a single handle. Stand sideways to the stack, holding the handle in the hand furthest from it.', 'With a soft bend in the elbow, raise the arm out to the side until roughly shoulder height, then lower under control. Complete all reps, then switch sides.', 'Exhale as the arm raises, inhale as it lowers.', ARRAY['Using momentum by shrugging or swinging the torso', 'Raising the arm above shoulder height and stressing the joint', 'Gripping the handle too tightly, which shifts load into the wrist and forearm']::text[], 'low', 'cable_handle', 'One hand works at a time against the cable stack; keep grip relaxed since the cable — not the wrist — bears the resistance.', 'The constant cable tension with a light setting and relaxed grip makes this a safe, effective shoulder isolation move for the injured right forearm.', '{}', null, 12, 15, 'Add one stack increment once both sides complete 15 strict reps without swinging.', ARRAY['dumbbell-lateral-raise', 'shoulder-press-machine']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('dumbbell-lateral-raise', 'Dumbbell Lateral Raise', ARRAY['shoulders']::text[], ARRAY['traps']::text[], 'isolation_extension', ARRAY['dumbbell']::text[], false, false, 'per_hand', 'Stand tall holding a light dumbbell in each hand at your sides, palms facing your body, soft bend in the elbows.', 'Raise both arms out to the sides until roughly shoulder height, then lower under control back to the start.', 'Exhale as the arms raise, inhale as they lower.', ARRAY['Using body momentum/swinging to heave the dumbbells up', 'Going too heavy and shrugging the traps instead of raising with the shoulder', 'Letting the wrists bend downward under the dumbbell weight']::text[], 'low', 'neutral', 'Each dumbbell is loaded independently but this is a light isolation move — stay well under the 25kg cap.', 'Use light dumbbells and keep wrists firm and neutral; the lateral-raise lever arm can amplify strain on the forearm if the weight creeps up, so prefer the cable version on higher-fatigue days.', ARRAY['Do not exceed 25kg per dumbbell (in practice use far lighter loads for this isolation move)']::text[], 25, 12, 15, 'Add the smallest available dumbbell increment once 15 strict reps are achieved without momentum.', ARRAY['cable-lateral-raise']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('bent-over-dumbbell-rear-delt-fly', 'Bent-Over Dumbbell Rear-Delt Fly', ARRAY['shoulders']::text[], ARRAY['back', 'traps']::text[], 'isolation_extension', ARRAY['dumbbell']::text[], false, false, 'per_hand', 'Hold a light dumbbell in each hand, hinge forward at the hips until the torso is close to parallel with the floor, knees softly bent, arms hanging with a slight elbow bend.', 'Raise both arms out to the sides in a wide arc, squeezing the shoulder blades together at the top, then lower under control.', 'Exhale as the arms raise and squeeze, inhale as they lower.', ARRAY['Standing too upright and turning it into a lateral raise', 'Using heavy weight and jerking the torso to generate momentum', 'Rounding the lower back instead of hinging with a flat spine']::text[], 'low', 'neutral', 'Each dumbbell is loaded independently; use light weight per hand — this is a light isolation exercise, well under the 25kg cap.', 'Keep the weight light and the wrist relaxed and neutral throughout; this is a low-load, low-risk exercise for the plated forearm as long as momentum is avoided.', ARRAY['Do not exceed 25kg per dumbbell (in practice use very light loads, typically under 8kg per hand)']::text[], 25, 12, 15, 'Add the smallest available dumbbell increment only once 15 strict, momentum-free reps are achieved.', ARRAY['rear-delt-cable-fly', 'cable-lateral-raise']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('rear-delt-cable-fly', 'Rear-Delt Cable Fly', ARRAY['shoulders']::text[], ARRAY['back', 'traps']::text[], 'isolation_extension', ARRAY['rear_delt_cable_station']::text[], false, false, 'machine_stack', 'Set both pulleys of a rear-delt cable station to chest height and cross the handles (right hand takes left pulley and vice versa). Stand centered between them.', 'Pull both handles out and back in a wide arc until arms are roughly in line with the shoulders, squeezing the rear delts, then return under control.', 'Exhale as the arms sweep back, inhale as they return.', ARRAY['Using the biceps to bend and pull instead of a straight-arm arc', 'Leaning the torso back to cheat the weight through', 'Choosing too heavy a pin weight and losing the rear-delt squeeze']::text[], 'low', 'cable_handle', 'Both hands work simultaneously on a dedicated dual-pulley cable station; load is set independently on each pulley.', 'This machine is not currently in the home setup — it is listed here for programme completeness only; use the dumbbell rear-delt fly at home instead.', ARRAY['Equipment (rear_delt_cable_station) not currently available at home']::text[], null, 12, 15, 'Add one pin increment on each pulley once 15 reps are hit with a clean rear-delt squeeze.', ARRAY['bent-over-dumbbell-rear-delt-fly']::text[], null, false) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('front-raise-cable', 'Cable Front Raise', ARRAY['shoulders']::text[], ARRAY['core']::text[], 'isolation_extension', ARRAY['cable_stack']::text[], false, false, 'machine_stack', 'Attach a straight bar to the low pulley. Stand facing away from the stack, holding the bar in front of your thighs with both hands.', 'Keeping the arms nearly straight, raise the bar in front of you to shoulder height, then lower under control.', 'Exhale raising the bar, inhale lowering it.', ARRAY['Swinging the torso backward to help lift the bar', 'Raising above shoulder height and losing tension', 'Gripping too hard and fatiguing the forearm before the shoulder']::text[], 'low', 'cable_handle', 'Both hands share a single bar attachment on the cable stack.', 'Constant, controllable cable tension with a relaxed grip keeps this safe for the injured right forearm.', '{}', null, 12, 15, 'Add one stack increment once 15 reps are completed with a strict, swing-free raise.', ARRAY['dumbbell-lateral-raise', 'shoulder-press-machine']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('hammer-curl', 'Dumbbell Hammer Curl', ARRAY['biceps']::text[], ARRAY['forearms']::text[], 'isolation_flexion', ARRAY['dumbbell']::text[], false, false, 'per_hand', 'Stand tall holding a dumbbell in each hand at your sides with a neutral, palms-facing-in grip.', 'Curl both dumbbells up toward the shoulders while keeping the palms facing each other throughout, then lower under control.', 'Exhale curling up, inhale lowering down.', ARRAY['Swinging the torso or using the hips to heave the weight up', 'Letting the elbows drift forward instead of staying pinned to the sides', 'Not fully extending the arms at the bottom of each rep']::text[], 'low', 'neutral', 'Each dumbbell is loaded independently; both hands are capped at 25kg, though the neutral grip keeps this comfortable for the forearm even near that limit.', 'The neutral (palms-in) grip is the most forearm-friendly curl variation available and is well suited to the titanium-plated right forearm; still respect the 25kg per-hand cap.', ARRAY['Do not exceed 25kg per dumbbell']::text[], 25, 8, 12, 'Add the smallest available dumbbell increment once both arms complete 12 strict reps.', ARRAY['cable-curl', 'dumbbell-bicep-curl']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('cable-curl', 'Cable Curl', ARRAY['biceps']::text[], ARRAY['forearms']::text[], 'isolation_flexion', ARRAY['cable_curl_station']::text[], false, false, 'machine_stack', 'Attach a straight or EZ bar to the low pulley of the cable curl station. Stand facing the stack, arms extended down holding the bar with an underhand grip.', 'Curl the bar up toward the shoulders by bending the elbows, keeping the upper arms fixed at your sides, then lower under control.', 'Exhale curling up, inhale lowering down.', ARRAY['Letting the elbows swing forward to cheat the weight up', 'Using the shoulders/back to help initiate the curl', 'Only performing the top half of the range of motion']::text[], 'low', 'cable_handle', 'Both hands share a single bar on the cable stack; the constant cable tension is gentler on the wrist than a free dumbbell curl at the same effective load.', 'The cable''s constant, smooth resistance avoids the momentary peak-load spikes of a free dumbbell curl, making this a good low-wrist-stress biceps option.', '{}', null, 10, 15, 'Add one stack increment once 15 reps are completed with strict elbow position.', ARRAY['hammer-curl', 'dumbbell-bicep-curl']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('dumbbell-bicep-curl', 'Standing Dumbbell Bicep Curl', ARRAY['biceps']::text[], ARRAY['forearms']::text[], 'isolation_flexion', ARRAY['dumbbell']::text[], false, false, 'per_hand', 'Stand tall with a dumbbell in each hand at your sides, palms facing forward (supinated grip).', 'Curl both dumbbells up toward the shoulders, keeping elbows pinned to your sides, then lower under control to full extension.', 'Exhale curling up, inhale lowering down.', ARRAY['Swinging the dumbbells up using momentum from the hips', 'Letting the wrists curl/flex extra at the top instead of staying firm', 'Not fully straightening the arms at the bottom']::text[], 'moderate', 'supinated', 'Each dumbbell is loaded independently and capped at 25kg per hand; the supinated grip loads the wrist more than a neutral hammer curl, so favour hammer curls on higher-fatigue days.', 'A fully supinated grip increases torque through the wrist compared with a neutral grip — keep the wrist firm and straight, and prefer hammer curls if the forearm feels fatigued.', ARRAY['Do not exceed 25kg per dumbbell', 'Switch to hammer curls if wrist rotation causes discomfort']::text[], 25, 8, 12, 'Add the smallest available dumbbell increment once 12 reps are completed for all sets.', ARRAY['hammer-curl', 'cable-curl']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('concentration-curl', 'Dumbbell Concentration Curl', ARRAY['biceps']::text[], ARRAY['forearms']::text[], 'isolation_flexion', ARRAY['dumbbell', 'bench']::text[], false, true, 'per_hand', 'Sit on a bench with legs spread, lean forward slightly, and brace the back of the working arm against the inside of the thigh, dumbbell hanging straight down.', 'Curl the dumbbell up toward the shoulder with a slow, controlled motion, squeezing the biceps at the top, then lower fully. Complete all reps, then switch sides.', 'Exhale curling up, inhale lowering down.', ARRAY['Letting the elbow drift off the thigh for leverage', 'Rushing the eccentric (lowering) portion', 'Twisting the torso to assist the lift']::text[], 'low', 'supinated', 'Only one hand is loaded at a time; cap the right hand at 25kg, though this isolation move is typically performed far lighter.', 'The braced elbow removes swing and keeps load predictable on the wrist; use a light dumbbell and stop if any twisting strain is felt in the forearm.', ARRAY['Right-hand load must not exceed 25kg']::text[], 25, 10, 15, 'Add the smallest available dumbbell increment once both arms complete 15 slow, controlled reps.', ARRAY['cable-curl', 'dumbbell-bicep-curl']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('triceps-rope-pushdown', 'Triceps Rope Pushdown', ARRAY['triceps']::text[], '{}', 'isolation_extension', ARRAY['triceps_rope', 'cable_stack']::text[], false, false, 'machine_stack', 'Attach the rope to the high pulley of the cable stack. Stand facing the stack, grip the rope ends with a neutral grip, elbows pinned to your sides.', 'Push the rope down and slightly apart at the bottom until the arms are fully extended, then let it rise under control back to the start without letting the elbows drift forward.', 'Exhale pushing down, inhale on the controlled return.', ARRAY['Letting the elbows travel forward away from the torso', 'Using body weight/leaning to push the weight down', 'Not achieving full elbow extension at the bottom']::text[], 'low', 'neutral', 'Both hands share the rope attachment on a single cable stack; the neutral grip on the rope ends is very forearm-friendly.', 'The rope''s neutral grip and smooth cable resistance make this the safest and most recommended triceps exercise for the plated right forearm.', '{}', null, 10, 15, 'Add one stack increment once 15 reps are completed with full lockout and no elbow drift.', ARRAY['overhead-cable-triceps-extension', 'dumbbell-triceps-kickback']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('overhead-cable-triceps-extension', 'Overhead Cable Triceps Extension', ARRAY['triceps']::text[], '{}', 'isolation_extension', ARRAY['cable_stack', 'triceps_rope']::text[], false, false, 'machine_stack', 'Attach the rope to a low pulley. Face away from the stack, hold the rope overhead with both hands, elbows bent and pointed forward.', 'Extend the arms forward and up until nearly straight, feeling a stretch in the triceps at the start, then return under control.', 'Exhale extending the arms, inhale on the return.', ARRAY['Letting the elbows flare outward instead of staying forward and fixed', 'Arching the lower back to generate momentum', 'Using too short a range of motion']::text[], 'low', 'neutral', 'Both hands share the rope attachment on a single cable stack.', 'The rope''s neutral grip and cable resistance keep wrist stress low, making this a safe triceps option for the plated forearm.', '{}', null, 10, 15, 'Add one stack increment once 15 controlled reps are achieved with a full stretch and lockout.', ARRAY['triceps-rope-pushdown', 'dumbbell-triceps-kickback']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('dumbbell-triceps-kickback', 'Dumbbell Triceps Kickback', ARRAY['triceps']::text[], '{}', 'isolation_extension', ARRAY['dumbbell', 'bench']::text[], false, true, 'per_hand', 'Place the left knee and hand on a bench for support, torso roughly parallel to the floor, right upper arm held tight to the torso with the elbow bent 90 degrees, dumbbell in hand.', 'Extend the forearm back until the arm is straight, squeezing the triceps, then return under control to the bent position. Complete all reps, then switch sides.', 'Exhale extending the arm back, inhale on the return.', ARRAY['Letting the upper arm drop and swing instead of staying fixed and parallel to the torso', 'Using momentum from the shoulder instead of isolating the elbow extension', 'Going too heavy, which forces the wrist to compensate for control']::text[], 'moderate', 'neutral', 'Only one hand is loaded at a time; cap the right hand at 25kg, though this isolation move is typically performed with light dumbbells.', 'Keep the dumbbell light — the extended-arm lever at the bottom of the kickback puts meaningful strain on the wrist and forearm if overloaded; stay well under the 25kg cap.', ARRAY['Right-hand load must not exceed 25kg', 'Avoid if elbow lockout causes forearm discomfort']::text[], 25, 10, 15, 'Add the smallest available dumbbell increment once both arms complete 15 strict reps.', ARRAY['triceps-rope-pushdown', 'overhead-cable-triceps-extension']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('bench-dip', 'Bench Dip', ARRAY['triceps']::text[], ARRAY['chest', 'shoulders']::text[], 'vertical_push', ARRAY['bench', 'bodyweight']::text[], true, false, 'bodyweight', 'Sit on the edge of a bench, hands gripping the edge next to your hips, legs extended out in front, heels on the floor.', 'Lower your body by bending the elbows until the upper arms are roughly parallel with the floor, then press back up to full extension.', 'Inhale lowering down, exhale pressing back up.', ARRAY['Lowering too far and straining the front of the shoulder', 'Letting the hips drift away from the bench', 'Locking the elbows out aggressively at the top']::text[], 'high', 'none', 'Bodyweight is supported through both wrists in an extended, weight-bearing position — the exact loading pattern to avoid with the titanium plate.', 'Bench dips load the wrist in extension while weight-bearing, similar to a push-up; not recommended for the plated right forearm. Use the triceps rope pushdown instead.', ARRAY['Not selectable by default due to weight-bearing wrist extension', 'Avoid until cleared by a physician']::text[], null, 8, 15, 'Not applicable while contraindicated; if medically cleared, progress by elevating the feet before adding external load.', ARRAY['triceps-rope-pushdown', 'overhead-cable-triceps-extension']::text[], null, false) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('cable-wrist-curl', 'Cable Wrist Curl', ARRAY['forearms']::text[], '{}', 'isolation_flexion', ARRAY['cable_stack']::text[], false, false, 'machine_stack', 'Attach a straight bar to the low pulley. Kneel or sit facing the stack, forearms resting on your thighs, wrists hanging just past the knees holding the bar with an underhand grip.', 'Curl the bar upward using only the wrists, then lower under control to a full stretch.', 'Exhale curling the wrists up, inhale lowering back down.', ARRAY['Using the forearms/elbows to swing the weight instead of isolating the wrist', 'Going too heavy for a small joint movement', 'Rushing through the stretch position at the bottom']::text[], 'moderate', 'cable_handle', 'Both hands share the bar on a single, adjustable cable stack, so load can be dialled in very precisely — start light.', 'Direct wrist flexion work should only be attempted well within a pain-free range and at low weight, given the titanium plate; stop immediately if there is any pinching or sharp sensation.', ARRAY['Not selectable by default — direct loaded wrist flexion is higher-risk for the plated forearm', 'Discontinue immediately if any pain, clicking, or instability is felt at the fracture site', 'Only attempt if specifically cleared by a physician for direct wrist loading']::text[], null, 12, 20, 'Add the smallest available stack increment only with physician clearance, and only once 20 pain-free reps are achieved.', ARRAY['hammer-curl', 'farmers-carry']::text[], null, false) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('farmers-carry', 'Dumbbell Farmer''s Carry', ARRAY['forearms']::text[], ARRAY['traps', 'core', 'full_body']::text[], 'carry', ARRAY['dumbbell', 'floor_space']::text[], true, false, 'per_hand', 'Stand between two dumbbells on the floor, hinge down keeping a flat back, and grip one dumbbell in each hand.', 'Stand up tall with the dumbbells at your sides, shoulders back and down, and walk forward for the prescribed distance or time with a controlled, even gait.', 'Breathe steadily and rhythmically throughout the carry; do not hold your breath.', ARRAY['Letting the shoulders round forward or shrug up under the load', 'Taking short, hurried steps instead of a controlled walking pace', 'Gripping so hard that the forearm fatigues before the intended muscles']::text[], 'moderate', 'neutral', 'Each dumbbell is carried in one hand independently; both hands are capped at 25kg so the right hand is never asked to grip beyond its limit.', 'This is a static loaded grip hold — keep both dumbbells at or under 25kg each and stop the set immediately if the right forearm starts to ache or shake excessively.', ARRAY['Do not exceed 25kg per hand', 'Stop immediately if grip fatigue causes the wrist to twist or buckle']::text[], 25, 1, 1, 'Increase carry distance or duration before increasing load; only add weight once the current load feels easily controlled for the full carry, up to 25kg per hand.', ARRAY['standing-calf-raise']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('leg-press', 'Leg Press', ARRAY['quads']::text[], ARRAY['glutes', 'hamstrings']::text[], 'squat', ARRAY['leg_press_machine']::text[], true, false, 'machine_stack', 'Sit in the machine with feet shoulder-width apart on the platform, mid-foot placement, back flat against the pad.', 'Release the safety catches and lower the platform by bending the knees toward the chest until roughly 90 degrees, then press back up to near lockout without slamming the knees straight.', 'Inhale as the platform lowers, exhale as you press it back up.', ARRAY['Letting the knees cave inward during the press', 'Lowering so far that the lower back rounds off the pad', 'Locking the knees out hard and aggressively at the top']::text[], 'low', 'none', 'Not a hand-loaded exercise — the machine bears all resistance through the legs and hips.', 'A machine-based lower-body compound with zero grip demand, making it ideal for building leg strength without stressing the injured forearm at all.', '{}', null, 8, 12, 'Add one plate/stack increment once all sets reach 12 reps with full, controlled range of motion.', ARRAY['leg-press-wide-stance', 'goblet-squat']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('leg-press-wide-stance', 'Leg Press (Wide Stance)', ARRAY['quads']::text[], ARRAY['glutes', 'hamstrings']::text[], 'squat', ARRAY['leg_press_machine']::text[], true, false, 'machine_stack', 'Sit in the machine with feet placed wide, toes turned out slightly, near the outer edges of the platform.', 'Lower the platform under control by bending the knees out over the toes, then press back up to near lockout, emphasising the inner thighs and glutes.', 'Inhale lowering, exhale pressing up.', ARRAY['Letting the knees collapse inward instead of tracking over the toes', 'Using a stance so wide that the hips lift off the pad', 'Rushing the eccentric (lowering) phase']::text[], 'low', 'none', 'Not a hand-loaded exercise — a wide-stance variation of the standard leg press for glute/inner-thigh emphasis.', 'Same zero-grip-demand safety profile as the standard leg press; a good rotation exercise to vary hip and knee angle without any added wrist risk.', '{}', null, 8, 12, 'Add one plate/stack increment once all sets reach 12 reps with knees tracking cleanly over the toes.', ARRAY['leg-press', 'dumbbell-sumo-squat']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('goblet-squat', 'Dumbbell Goblet Squat', ARRAY['quads']::text[], ARRAY['glutes', 'core']::text[], 'squat', ARRAY['dumbbell']::text[], true, false, 'total', 'Hold one dumbbell vertically against your chest with both hands cupping the top head, feet shoulder-width apart.', 'Squat down by bending the knees and hips, keeping the chest up and the dumbbell close to the body, until thighs are roughly parallel to the floor, then drive back up.', 'Inhale on the way down, exhale driving back up.', ARRAY['Letting the knees cave inward on the way up', 'Leaning too far forward and losing the upright torso position', 'Not reaching an adequate squat depth']::text[], 'low', 'neutral', 'The single dumbbell is held with both hands together, so the load is capped as a TOTAL (not per hand) at 25kg to protect the right forearm.', 'Because both hands share the single dumbbell, cap the TOTAL load at 25kg — this keeps the right hand''s actual share well under its individual limit while still training the legs hard.', ARRAY['Do not exceed 25kg total dumbbell weight']::text[], 25, 10, 15, 'Add the smallest available dumbbell increment once 15 reps are completed with full depth, up to the 25kg total cap; beyond that, progress via leg press instead.', ARRAY['leg-press', 'dumbbell-sumo-squat']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('leg-extension', 'Leg Extension', ARRAY['quads']::text[], '{}', 'isolation_extension', ARRAY['leg_extension_machine']::text[], false, false, 'machine_stack', 'Sit in the machine with the back against the pad and the shin pad resting just above the ankles, knees aligned with the machine''s pivot.', 'Extend the legs until nearly straight, squeezing the quads at the top, then lower under control back to the start.', 'Exhale extending the legs, inhale lowering back down.', ARRAY['Using momentum by kicking the weight up instead of a controlled extension', 'Slamming the weight stack down on the way back', 'Lifting the hips off the seat to help move heavier loads']::text[], 'low', 'none', 'Not a hand-loaded exercise — hands only lightly grip the side handles for stability.', 'A pure quad isolation machine with essentially no grip demand, making it fully safe for the plated forearm.', '{}', null, 10, 15, 'Add one stack increment once all sets reach 15 reps with a full, controlled squeeze at the top.', ARRAY['leg-press', 'goblet-squat']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('walking-lunges', 'Dumbbell Walking Lunges', ARRAY['quads']::text[], ARRAY['glutes', 'hamstrings', 'core']::text[], 'lunge', ARRAY['dumbbell', 'floor_space']::text[], true, true, 'per_hand', 'Stand tall holding a dumbbell in each hand at your sides, with enough open floor space ahead to take 8-12 continuous steps.', 'Step forward into a lunge, lowering the back knee toward the floor while keeping the front shin roughly vertical, then drive through the front foot to step into the next lunge on the opposite leg.', 'Inhale as you step down into the lunge, exhale as you drive up and forward.', ARRAY['Letting the front knee travel far past the toes on every step', 'Taking steps too short, causing the back knee to slam the floor', 'Leaning the torso forward instead of staying upright']::text[], 'low', 'neutral', 'Each dumbbell is carried in one hand at the side, statically, not actively lifted; both hands are capped at 25kg for symmetry with the right-hand limit.', 'Dumbbells are held statically at the sides here (not pressed or curled), so wrist demand is low; keep both at or under 25kg and prioritise balance and control over speed.', ARRAY['Do not exceed 25kg per dumbbell']::text[], 25, 8, 12, 'Increase step count first, then add the smallest available dumbbell increment once 12 steps per leg feel controlled, up to the 25kg cap.', ARRAY['leg-press', 'dumbbell-sumo-squat']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('bodyweight-split-squat', 'Bodyweight Split Squat', ARRAY['quads']::text[], ARRAY['glutes', 'hamstrings']::text[], 'lunge', ARRAY['bodyweight', 'floor_space']::text[], true, true, 'bodyweight', 'Stand in a staggered stance with one foot forward and one foot back, torso upright, hands on hips or held loosely at your sides.', 'Lower straight down by bending both knees until the back knee nearly touches the floor, then drive up through the front foot. Complete all reps, then switch legs.', 'Inhale lowering down, exhale driving back up.', ARRAY['Letting the front knee cave inward', 'Taking too narrow or too short a stance, limiting range of motion', 'Leaning the torso too far forward']::text[], 'low', 'none', 'No hand loading at all — hands are free at the sides or on the hips throughout.', 'A fully bodyweight lower-body movement with zero wrist or grip involvement, ideal as a warm-up or accessory move for the plated forearm.', '{}', null, 10, 15, 'Once 15 controlled reps per leg feel easy, progress to walking lunges with light dumbbells.', ARRAY['walking-lunges', 'leg-press']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('smith-machine-squat', 'Smith Machine Squat', ARRAY['quads']::text[], ARRAY['glutes', 'hamstrings']::text[], 'squat', ARRAY['smith_machine']::text[], true, false, 'machine_stack', 'Position the bar across the upper back/traps under the fixed Smith machine track, feet shoulder-width apart and slightly forward of the bar path.', 'Unrack the bar, squat down by bending the knees and hips until thighs are roughly parallel to the floor, then drive back up to standing.', 'Inhale on the way down, exhale driving back up.', ARRAY['Placing the feet directly under the bar, forcing an unnatural knee path', 'Rounding the lower back at the bottom of the squat', 'Rushing the unrack/re-rack and catching the bar path awkwardly']::text[], 'moderate', 'pronated', 'The bar rests across the upper back; hands only stabilise it with a wide overhand grip, but the fixed bar path still requires wrist extension to hold the grip under load.', 'This equipment is not currently available at home; the fixed bar also demands a loaded overhand wrist position to steady it, so this is not recommended for the plated forearm even if access becomes available — use the leg press instead.', ARRAY['Equipment (smith_machine) not currently available at home', 'Loaded overhand grip on the fixed bar is not ideal for the titanium-plated right forearm']::text[], null, 6, 10, 'Not currently applicable — no access to equipment; use the leg press progression instead.', ARRAY['leg-press', 'goblet-squat']::text[], null, false) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('dumbbell-romanian-deadlift', 'Dumbbell Romanian Deadlift', ARRAY['hamstrings']::text[], ARRAY['glutes', 'back']::text[], 'hinge', ARRAY['dumbbell']::text[], true, false, 'per_hand', 'Stand tall holding a dumbbell in each hand in front of your thighs, feet hip-width apart, soft bend in the knees.', 'Hinge at the hips, pushing them back while lowering the dumbbells close to the legs, keeping a flat back, until you feel a stretch in the hamstrings, then drive the hips forward to stand back up.', 'Inhale as you hinge down, exhale as you drive the hips forward to stand.', ARRAY['Rounding the lower back instead of hinging with a flat spine', 'Bending the knees too much and turning it into a squat', 'Letting the dumbbells drift away from the legs, adding leverage stress to the low back and grip']::text[], 'moderate', 'neutral', 'Each dumbbell is loaded independently; both hands are capped at 25kg — the hang position also demands sustained grip, so stop the set if grip fatigues before the hamstrings.', 'The dumbbells hang in a static grip through the full range, which loads the forearm continuously — keep both at or under 25kg per hand and use lifting straps only if approved, never chalk/grip aids that encourage overgripping.', ARRAY['Do not exceed 25kg per dumbbell', 'Stop the set if grip gives out before the hamstrings/glutes']::text[], 25, 8, 12, 'Increase both dumbbells by the smallest increment once 12 reps are hit with a flat back and full stretch, up to the 25kg cap.', ARRAY['leg-press-wide-stance', 'goblet-squat']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('single-leg-dumbbell-rdl', 'Single-Leg Dumbbell RDL', ARRAY['hamstrings']::text[], ARRAY['glutes', 'core']::text[], 'hinge', ARRAY['dumbbell']::text[], true, true, 'per_hand', 'Stand on one leg holding a dumbbell in the opposite hand, soft bend in the standing knee.', 'Hinge forward at the hip while extending the free leg straight back for balance, lowering the dumbbell toward the floor with a flat back, then reverse the motion to stand tall. Complete all reps, then switch sides.', 'Inhale hinging down, exhale returning to standing.', ARRAY['Rotating the hips open instead of keeping them square to the floor', 'Rounding the back to reach further down', 'Using too much weight for the balance demand, causing the wrist to overgrip for stability']::text[], 'moderate', 'neutral', 'Only one hand is loaded at a time; cap the right hand at 25kg — use a light weight initially since balance is the main challenge.', 'Balance demand can cause an involuntary overgrip if the weight is too heavy — use light dumbbells well under the 25kg cap until balance is confident, especially when the right hand is loaded.', ARRAY['Right-hand load must not exceed 25kg']::text[], 25, 8, 12, 'Add the smallest available dumbbell increment only once balance is fully controlled for 12 reps per leg.', ARRAY['dumbbell-romanian-deadlift', 'leg-press-wide-stance']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('lying-leg-curl', 'Lying Leg Curl', ARRAY['hamstrings']::text[], ARRAY['glutes']::text[], 'isolation_flexion', ARRAY['leg_curl_machine']::text[], false, false, 'machine_stack', 'Lie face down on the machine with the ankle pad positioned just above the heels, knees aligned with the machine''s pivot point.', 'Curl the heels up toward the glutes, squeezing the hamstrings at the top, then lower under control back to the start.', 'Exhale curling the legs up, inhale lowering back down.', ARRAY['Lifting the hips off the pad to generate momentum', 'Using a jerky kick instead of a smooth curl', 'Not controlling the negative/lowering phase']::text[], 'low', 'none', 'Not a hand-loaded exercise — hands only lightly grip the front handles for stability.', 'This equipment is not currently available at home; when it is, it carries essentially zero wrist risk since it is a leg-only machine.', ARRAY['Equipment (leg_curl_machine) not currently available at home']::text[], null, 10, 15, 'Not currently applicable — no access to equipment; use the dumbbell Romanian deadlift for hamstring work instead.', ARRAY['dumbbell-romanian-deadlift', 'single-leg-dumbbell-rdl']::text[], null, false) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('dumbbell-sumo-squat', 'Dumbbell Sumo Squat', ARRAY['glutes']::text[], ARRAY['quads', 'hamstrings']::text[], 'squat', ARRAY['dumbbell']::text[], true, false, 'total', 'Stand with feet wider than shoulder width, toes turned out, holding one dumbbell vertically with both hands in front of the body.', 'Squat straight down by bending the knees out over the toes, keeping the dumbbell close to the body, until thighs are close to parallel, then drive back up through the heels.', 'Inhale descending, exhale driving back up.', ARRAY['Letting the knees collapse inward instead of tracking over the toes', 'Rounding the upper back to keep the dumbbell close', 'Not reaching adequate depth']::text[], 'low', 'neutral', 'The single dumbbell is held with both hands together, so load is capped as a TOTAL (not per hand) at 25kg to protect the right forearm.', 'Because both hands share one dumbbell, cap the TOTAL load at 25kg — this keeps grip demand on the right hand comfortably under its individual limit.', ARRAY['Do not exceed 25kg total dumbbell weight']::text[], 25, 10, 15, 'Add the smallest available dumbbell increment once 15 reps are completed with full depth, up to the 25kg total cap; progress further via leg press wide stance.', ARRAY['leg-press-wide-stance', 'goblet-squat']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('glute-bridge', 'Bodyweight Glute Bridge', ARRAY['glutes']::text[], ARRAY['hamstrings', 'core']::text[], 'hinge', ARRAY['bodyweight', 'floor_space']::text[], true, false, 'bodyweight', 'Lie on your back with knees bent, feet flat on the floor hip-width apart, arms relaxed at your sides.', 'Drive through the heels to lift the hips up until the body forms a straight line from shoulders to knees, squeeze the glutes at the top, then lower under control.', 'Exhale lifting the hips, inhale lowering back down.', ARRAY['Overarching the lower back instead of squeezing the glutes to extend the hips', 'Pushing through the toes instead of the heels', 'Rushing the tempo instead of pausing at the top']::text[], 'low', 'none', 'No hand loading — arms rest passively at the sides throughout.', 'A fully floor-based, zero-wrist-load glute exercise, completely safe for the plated forearm.', '{}', null, 12, 20, 'Progress to single-leg glute bridges once 20 double-leg reps feel easy.', ARRAY['dumbbell-sumo-squat', 'dumbbell-romanian-deadlift']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('dumbbell-step-up', 'Dumbbell Step-Up', ARRAY['glutes']::text[], ARRAY['quads', 'hamstrings']::text[], 'lunge', ARRAY['dumbbell', 'bench']::text[], true, true, 'per_hand', 'Stand facing a sturdy bench or step, holding a dumbbell in each hand at your sides.', 'Step one foot fully onto the bench, drive through that heel to stand up on top, then step back down under control. Complete all reps, then switch the leading leg.', 'Exhale driving up onto the bench, inhale stepping back down.', ARRAY['Pushing off the trailing leg instead of driving through the top leg', 'Using a step too high for current hip mobility', 'Losing balance and leaning heavily on the dumbbells for support']::text[], 'low', 'neutral', 'Each dumbbell is held statically at the side; both hands are capped at 25kg for symmetry with the right-hand limit.', 'Dumbbells are carried passively at the sides here, so wrist demand is minimal; keep both at or under 25kg and prioritise a stable step platform.', ARRAY['Do not exceed 25kg per dumbbell']::text[], 25, 8, 12, 'Add the smallest available dumbbell increment once 12 controlled reps per leg are achieved, up to the 25kg cap.', ARRAY['walking-lunges', 'leg-press']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('standing-calf-raise', 'Dumbbell Standing Calf Raise', ARRAY['calves']::text[], '{}', 'calf_raise', ARRAY['dumbbell']::text[], false, false, 'per_hand', 'Stand tall holding a dumbbell in each hand at your sides, feet hip-width apart, balls of the feet on a slightly raised surface if available.', 'Rise up onto the toes as high as possible, squeezing the calves at the top, then lower under control to a full stretch at the bottom.', 'Exhale rising up, inhale lowering back down.', ARRAY['Bouncing at the bottom instead of pausing for a full stretch', 'Rushing through reps without a full range of motion', 'Letting the ankles roll outward or inward instead of tracking straight']::text[], 'low', 'neutral', 'Each dumbbell is held statically at the side; both hands are capped at 25kg for symmetry with the right-hand limit.', 'Dumbbells are held passively at the sides while the calves do the work, so wrist demand is minimal; keep both at or under 25kg per hand.', ARRAY['Do not exceed 25kg per dumbbell']::text[], 25, 12, 20, 'Add the smallest available dumbbell increment once 20 reps are completed with a full stretch and pause at the top.', ARRAY['seated-calf-raise', 'leg-press']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('seated-calf-raise', 'Dumbbell Seated Calf Raise', ARRAY['calves']::text[], '{}', 'calf_raise', ARRAY['dumbbell', 'bench']::text[], false, false, 'per_hand', 'Sit on the edge of a bench with feet flat on the floor, balls of the feet on a raised block if available, and rest one dumbbell upright on each knee, holding it steady with the hand.', 'Raise the heels as high as possible, squeezing the calves, then lower under control to a full stretch.', 'Exhale rising up, inhale lowering back down.', ARRAY['Letting the dumbbell roll off the knee instead of holding it steady', 'Using a partial range of motion', 'Rushing the tempo instead of pausing at the top and bottom']::text[], 'low', 'neutral', 'Each dumbbell rests on a knee and is only steadied by the hand, not actively lifted by the wrist; both are capped at 25kg for consistency.', 'The dumbbell''s weight is supported by the thigh, not the wrist, so grip demand is very low — safe for the plated forearm at or under the 25kg per-hand cap.', ARRAY['Do not exceed 25kg per dumbbell']::text[], 25, 12, 20, 'Add the smallest available dumbbell increment once 20 reps are completed with a full, controlled stretch.', ARRAY['standing-calf-raise']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('single-leg-calf-raise', 'Bodyweight Single-Leg Calf Raise', ARRAY['calves']::text[], '{}', 'calf_raise', ARRAY['bodyweight']::text[], false, true, 'bodyweight', 'Stand on one leg near a wall or rail for light balance support, other foot lifted slightly off the floor.', 'Rise up onto the toes of the standing leg as high as possible, then lower under control to a full stretch. Complete all reps, then switch legs.', 'Exhale rising up, inhale lowering back down.', ARRAY['Using the support hand to pull rather than just balance', 'Rushing through reps without a full stretch at the bottom', 'Letting the ankle wobble side to side instead of tracking straight']::text[], 'low', 'none', 'No meaningful hand loading — any hand contact with a wall or rail is for balance only.', 'A fully bodyweight calf exercise with no wrist loading; a good option on days the forearm feels fatigued from other lifts.', '{}', null, 12, 20, 'Once 20 reps per leg are easy, progress to holding a single light dumbbell in the free hand.', ARRAY['standing-calf-raise', 'seated-calf-raise']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('cable-crunch', 'Cable Kneeling Crunch', ARRAY['core']::text[], '{}', 'isolation_flexion', ARRAY['cable_stack', 'triceps_rope']::text[], false, false, 'machine_stack', 'Attach the rope to the high pulley and kneel facing the stack, holding the rope ends beside your head or shoulders.', 'Crunch the torso down by flexing the abs, bringing the elbows toward the thighs, then return under control to the start without letting the hips move.', 'Exhale crunching down, inhale on the return.', ARRAY['Pulling with the arms instead of flexing the spine with the abs', 'Using the hips to rock the weight instead of isolating the torso', 'Not achieving a full crunch/flexion at the bottom']::text[], 'low', 'neutral', 'Both hands loosely hold the rope near the head; the cable — not the grip — provides resistance.', 'The rope is held loosely near the head rather than gripped hard against resistance, so wrist strain is minimal; safe for the plated forearm.', '{}', null, 12, 20, 'Add one stack increment once 20 reps are completed with a full spinal flexion and controlled tempo.', ARRAY['plank', 'dead-bug']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('plank', 'Forearm Plank', ARRAY['core']::text[], ARRAY['shoulders']::text[], 'isolation_flexion', ARRAY['bodyweight']::text[], false, false, 'bodyweight', 'Rest on your forearms and toes, elbows directly under the shoulders, body in a straight line from head to heels.', 'Hold the straight-line position, bracing the core and squeezing the glutes, for the prescribed duration without letting the hips sag or pike.', 'Breathe slowly and steadily throughout the hold; do not hold your breath.', ARRAY['Letting the hips sag toward the floor', 'Piking the hips up too high', 'Holding the breath instead of breathing steadily']::text[], 'moderate', 'none', 'Bodyweight is distributed through both forearms rather than the wrists directly, which is gentler than a push-up plank, but sustained forearm weight-bearing still loads the injured area.', 'Even though weight rests on the forearms rather than the wrists, sustained pressure directly over the fracture site is best avoided — use the cable crunch instead until specifically cleared.', ARRAY['Not selectable by default — sustained forearm weight-bearing over the plate site is best avoided', 'Avoid until cleared by a physician for forearm weight-bearing holds']::text[], null, 20, 45, 'Not applicable while contraindicated; if medically cleared, progress hold duration (seconds) in 5-second increments before adding any external load.', ARRAY['cable-crunch', 'dead-bug']::text[], null, false) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('weighted-plank', 'Weighted Plank', ARRAY['core']::text[], ARRAY['shoulders']::text[], 'isolation_flexion', ARRAY['bodyweight', 'dumbbell']::text[], false, false, 'bodyweight', 'Set up in a standard forearm plank position with a weight plate or dumbbell placed across the upper back.', 'Hold the straight-line plank position under the added load for the prescribed duration, bracing the core throughout.', 'Breathe slowly and steadily; do not hold your breath under the added load.', ARRAY['Letting the hips sag under the extra weight', 'Using more weight than the core can stabilise, causing form breakdown', 'Holding the breath under load']::text[], 'high', 'none', 'External load adds directly to the weight already borne through the forearms, increasing sustained pressure on the injured site.', 'Adding external load on top of a forearm-bearing hold directly increases pressure at the plate site — explicitly not recommended for the plated right forearm. Use the cable crunch instead.', ARRAY['Not selectable by default — added load increases sustained pressure on the injured forearm', 'Avoid entirely until specifically cleared by a physician']::text[], null, 15, 30, 'Not applicable while contraindicated.', ARRAY['cable-crunch', 'dead-bug']::text[], null, false) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('dead-bug', 'Dead Bug', ARRAY['core']::text[], '{}', 'isolation_flexion', ARRAY['bodyweight', 'floor_space']::text[], false, true, 'bodyweight', 'Lie on your back with arms extended toward the ceiling and knees bent 90 degrees directly above the hips.', 'Slowly extend one arm overhead and the opposite leg straight out toward the floor while keeping the lower back pressed flat, then return to the start and alternate sides.', 'Exhale as the arm/leg extend out, inhale as they return to the start.', ARRAY['Letting the lower back arch off the floor', 'Moving too fast and losing control of the extension', 'Extending the limbs too far, forcing the back to arch to compensate']::text[], 'low', 'none', 'No load and no weight-bearing through the wrist or forearm at any point.', 'A fully floor-supported core exercise with zero forearm loading — an excellent, always-safe choice for the plated right forearm.', '{}', null, 10, 15, 'Slow the tempo and increase the hold at full extension once 15 clean reps per side are achieved.', ARRAY['cable-crunch']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('hanging-knee-raise', 'Hanging Knee Raise', ARRAY['core']::text[], ARRAY['forearms']::text[], 'isolation_flexion', ARRAY['bodyweight']::text[], false, false, 'bodyweight', 'Hang from a secure overhead bar with an overhand grip, arms fully extended, legs straight down.', 'Raise the knees up toward the chest by flexing the hips and abs, then lower under control back to a full hang.', 'Exhale raising the knees, inhale lowering back down.', ARRAY['Swinging the body to generate momentum instead of a controlled raise', 'Not achieving a full hang at the bottom of each rep', 'Shrugging the shoulders up instead of keeping them engaged and down']::text[], 'high', 'pronated', 'Full bodyweight hangs through both wrists in a fixed overhand grip for the entire set, which is a sustained high load on the forearm.', 'A dead hang places full bodyweight through the wrist and forearm in a fixed grip for the whole set — not recommended for the plated right forearm. Use the cable crunch instead.', ARRAY['Not selectable by default — sustained full-bodyweight hang loads the injured forearm directly', 'Avoid until specifically cleared by a physician for hanging/grip-bearing work']::text[], null, 8, 15, 'Not applicable while contraindicated.', ARRAY['cable-crunch', 'dead-bug']::text[], null, false) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('dumbbell-shrug', 'Dumbbell Shrug', ARRAY['traps']::text[], ARRAY['forearms']::text[], 'isolation_extension', ARRAY['dumbbell']::text[], false, false, 'per_hand', 'Stand tall holding a dumbbell in each hand at your sides, arms fully extended, shoulders relaxed.', 'Elevate the shoulders straight up toward the ears as high as possible, pause briefly, then lower under control.', 'Exhale shrugging up, inhale lowering back down.', ARRAY['Rolling the shoulders in a circular motion instead of a straight vertical shrug', 'Using momentum from the knees to help lift the weight', 'Not pausing at the top to maximise the contraction']::text[], 'moderate', 'neutral', 'Each dumbbell is held statically; both hands are capped at 25kg, and the static hang under load also demands sustained grip.', 'The dumbbells hang statically through a sustained grip for the whole set, so keep both at or under 25kg per hand and stop if grip fatigue sets in before the traps.', ARRAY['Do not exceed 25kg per dumbbell', 'Stop the set if grip gives out before the traps']::text[], 25, 10, 15, 'Add the smallest available dumbbell increment once 15 reps are completed with a full pause at the top, up to the 25kg cap.', ARRAY['cable-upright-row', 'farmers-carry']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('cable-upright-row', 'Cable Upright Row', ARRAY['traps']::text[], ARRAY['shoulders']::text[], 'vertical_pull', ARRAY['cable_stack']::text[], false, false, 'machine_stack', 'Attach a straight bar to the low pulley. Stand facing the stack holding the bar in front of your thighs with a close, overhand grip.', 'Pull the bar straight up along the body to roughly chest height, leading with the elbows, then lower under control.', 'Exhale pulling up, inhale lowering down.', ARRAY['Pulling the bar too high, which can pinch the shoulder joint', 'Leaning back to use momentum instead of a controlled pull', 'Using a grip so narrow it strains the wrists']::text[], 'low', 'cable_handle', 'Both hands share a single bar attachment on the cable stack; the smooth cable resistance is gentler than a free-weight shrug.', 'Cable resistance with a moderate, shoulder-width grip keeps wrist strain low, making this a safe trap/shoulder builder for the plated forearm.', '{}', null, 10, 15, 'Add one stack increment once 15 reps are completed with elbows leading and no shoulder pinching.', ARRAY['dumbbell-shrug', 'cable-lateral-raise']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('cable-shrug', 'Cable Shrug', ARRAY['traps']::text[], ARRAY['forearms']::text[], 'isolation_extension', ARRAY['cable_stack']::text[], false, false, 'machine_stack', 'Attach a straight bar to the low pulley. Stand facing the stack holding the bar with both hands, arms fully extended down.', 'Elevate the shoulders straight up toward the ears, pause briefly at the top, then lower under control.', 'Exhale shrugging up, inhale lowering back down.', ARRAY['Rolling the shoulders instead of a straight vertical shrug', 'Using the legs to bounce the weight up', 'Cutting the range of motion short at the top']::text[], 'low', 'cable_handle', 'Both hands share a single bar on the cable stack; the smooth constant tension is gentler on the sustained grip than a static dumbbell hang.', 'Cable resistance keeps the load smooth and adjustable in small increments, making this a lower-wrist-stress way to train the traps than a heavy static dumbbell shrug.', '{}', null, 10, 15, 'Add one stack increment once 15 reps are completed with a full pause at the top.', ARRAY['dumbbell-shrug', 'cable-upright-row']::text[], null, true) on conflict (slug) do nothing;
