insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('machine-reverse-fly', 'Machine Reverse Fly', ARRAY['shoulders']::text[], ARRAY['back', 'traps']::text[], 'horizontal_pull', ARRAY['chest_press_machine']::text[], false, false, 'machine_stack', 'Sit facing into the machine (reversed from the chest press position) with the handles in front of you at chest height.', 'Pull the handles out and back in a wide arc, squeezing the rear delts and upper back, then return under control to the start.', 'Exhale pulling the handles back, inhale returning them forward.', ARRAY['Using the arms to yank the handles instead of driving from the rear delts', 'Shrugging the shoulders up during the movement', 'Cutting the range of motion short']::text[], 'low', 'machine_handle', 'Both handles move on a single fixed stack; load is not split independently per hand.', 'A fixed machine handle keeps the wrist neutral and supported, making this the safest rear-delt option when a dedicated rear-delt cable station is not available.', '{}', null, 12, 15, 'Add one stack increment once 15 reps are completed with a full squeeze at the back.', ARRAY['bent-over-dumbbell-rear-delt-fly', 'rear-delt-cable-fly']::text[], null, true) on conflict (slug) do nothing;
