insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('single-arm-triceps-pushdown', 'Single-Arm Cable Triceps Pushdown', ARRAY['triceps']::text[], '{}', 'isolation_extension', ARRAY['cable_stack']::text[], false, true, 'machine_stack', 'Attach a single handle to the high pulley. Stand facing the stack, gripping the handle with one hand, elbow pinned to your side.', 'Push the handle down until the arm is fully extended, squeezing the triceps, then let it rise under control. Complete all reps, then switch sides.', 'Exhale pushing down, inhale on the controlled return.', ARRAY['Letting the elbow drift away from the torso', 'Rotating the torso to add momentum', 'Not achieving full lockout at the bottom']::text[], 'low', 'cable_handle', 'Only one hand works the cable at a time; the smooth cable resistance and relaxed handle grip are gentle on the wrist regardless of which hand is working.', 'Unilateral cable work with a relaxed handle grip is safe for the plated forearm — useful for addressing left/right strength differences without any free-weight wrist stabilisation demand.', '{}', null, 10, 15, 'Add one stack increment once both arms complete 15 reps with full lockout.', ARRAY['triceps-rope-pushdown', 'overhead-cable-triceps-extension']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('leg-press-single-leg', 'Single-Leg Leg Press', ARRAY['quads']::text[], ARRAY['glutes', 'hamstrings']::text[], 'squat', ARRAY['leg_press_machine']::text[], true, true, 'machine_stack', 'Sit in the machine and place one foot centered on the platform, the other foot resting off to the side or on the frame.', 'Lower the platform under control by bending the working knee toward the chest, then press back up to near lockout. Complete all reps, then switch legs.', 'Inhale lowering, exhale pressing up.', ARRAY['Letting the working knee cave inward', 'Using a much lighter load than needed to maintain control on one leg', 'Rushing the tempo instead of a controlled single-leg press']::text[], 'low', 'none', 'Not a hand-loaded exercise — the machine bears all resistance through one leg at a time.', 'Same zero-grip-demand safety profile as the standard leg press, with the added benefit of addressing left/right leg strength imbalances.', '{}', null, 8, 12, 'Add one plate/stack increment once both legs complete 12 reps with full control.', ARRAY['leg-press', 'walking-lunges']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('cable-pull-through', 'Cable Pull-Through', ARRAY['glutes']::text[], ARRAY['hamstrings', 'back']::text[], 'hinge', ARRAY['cable_stack']::text[], true, false, 'machine_stack', 'Attach a rope to the low pulley and stand facing away from the stack, straddling the cable with the rope between your legs, holding an end in each hand.', 'Hinge forward at the hips, letting the rope travel back between your legs, then drive the hips forward to stand up tall, squeezing the glutes at the top.', 'Inhale hinging back, exhale driving the hips forward.', ARRAY['Squatting instead of hinging at the hips', 'Rounding the lower back at the bottom of the hinge', 'Using the arms to pull the rope instead of driving with the hips']::text[], 'low', 'cable_handle', 'Both hands loosely hold one rope end each; the cable — not the grip — provides resistance throughout the hinge.', 'The rope is held loosely rather than gripped hard against a heavy static load, so wrist strain is minimal, making this a safe hip-hinge option for the plated forearm.', '{}', null, 10, 15, 'Add one stack increment once 15 reps are completed with a full hip hinge and glute squeeze.', ARRAY['dumbbell-romanian-deadlift', 'glute-bridge']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('single-leg-glute-bridge', 'Single-Leg Glute Bridge', ARRAY['glutes']::text[], ARRAY['hamstrings', 'core']::text[], 'hinge', ARRAY['bodyweight', 'floor_space']::text[], false, true, 'bodyweight', 'Lie on your back with knees bent, feet flat on the floor, then extend one leg straight out or hold it up toward the chest.', 'Drive through the planted heel to lift the hips up until the body forms a straight line, squeeze the glute at the top, then lower under control. Complete all reps, then switch legs.', 'Exhale lifting the hips, inhale lowering back down.', ARRAY['Letting the hips rotate/open toward the lifted leg', 'Overarching the lower back instead of driving through the glute', 'Rushing the tempo instead of pausing at the top']::text[], 'low', 'none', 'No hand loading — arms rest passively at the sides throughout.', 'A fully floor-based, zero-wrist-load glute exercise, completely safe for the plated forearm.', '{}', null, 10, 15, 'Once 15 reps per leg feel easy, progress to the dumbbell sumo squat for added load.', ARRAY['glute-bridge', 'dumbbell-sumo-squat']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('bodyweight-calf-raise', 'Bodyweight Standing Calf Raise', ARRAY['calves']::text[], '{}', 'calf_raise', ARRAY['bodyweight']::text[], false, false, 'bodyweight', 'Stand tall with feet hip-width apart, balls of the feet on a slightly raised surface if available, hands resting lightly on a wall for balance.', 'Rise up onto the toes as high as possible, pause and squeeze at the top, then lower under control to a full stretch.', 'Exhale rising up, inhale lowering back down.', ARRAY['Bouncing at the bottom instead of a controlled stretch', 'Rushing through reps without a full range of motion', 'Leaning heavily on the wall instead of balancing independently']::text[], 'low', 'none', 'No meaningful hand loading — any wall contact is for balance only.', 'A fully bodyweight calf exercise with no wrist loading; a good warm-up or high-rep finisher on days the forearm feels fatigued.', '{}', null, 15, 25, 'Once 25 reps feel easy, progress to the dumbbell standing calf raise for added load.', ARRAY['standing-calf-raise', 'seated-calf-raise']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('side-plank', 'Side Plank', ARRAY['core']::text[], ARRAY['shoulders']::text[], 'isolation_flexion', ARRAY['bodyweight']::text[], false, true, 'bodyweight', 'Lie on your side, prop yourself up on the forearm with the elbow directly under the shoulder, legs stacked and extended.', 'Lift the hips until the body forms a straight line from head to feet, hold the position, then lower under control. Complete the hold, then switch sides.', 'Breathe slowly and steadily throughout the hold; do not hold your breath.', ARRAY['Letting the hips sag toward the floor', 'Rotating the torso forward or backward instead of staying stacked', 'Holding the breath during the hold']::text[], 'moderate', 'none', 'Bodyweight rests through one forearm at a time rather than the wrist directly, but sustained pressure on the plated forearm side should be limited.', 'When performed on the right side, this loads the plated forearm with sustained bodyweight pressure — favour the left-side hold, or substitute the cable crunch for right-side core work until cleared.', ARRAY['Limit or avoid right-side holds that load the plated forearm directly', 'Discontinue if any discomfort is felt at the fracture site']::text[], null, 15, 30, 'Increase hold duration (seconds) in 5-second increments once the current hold feels controlled and pain-free.', ARRAY['cable-crunch', 'dead-bug']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('incline-treadmill-walk', 'Incline Treadmill Walk', ARRAY['full_body']::text[], ARRAY['glutes', 'calves', 'quads']::text[], 'cardio', ARRAY['treadmill']::text[], true, false, 'bodyweight', 'Step onto the treadmill, set a moderate incline (roughly 6-12%), and start at a comfortable walking pace.', 'Walk at a steady pace for the prescribed duration, holding the side rails only lightly if needed for balance, keeping the torso upright rather than leaning on the front console.', 'Breathe rhythmically and steadily throughout; settle into a pace you can sustain while holding a conversation.', ARRAY['Gripping the handrails tightly and leaning on them, which reduces the training effect and loads the wrists unnecessarily', 'Setting an incline or speed that forces an unnatural, shortened stride', 'Looking down at the feet instead of keeping the chest up and eyes forward']::text[], 'low', 'none', 'No hand loading required — hands should only rest lightly on the rails for balance, not bear weight.', 'Keep hands light on the rails rather than gripping and leaning, which would place sustained load through the wrist; this is otherwise a fully safe, low-impact cardio option for the plated forearm.', ARRAY['Avoid gripping/leaning heavily on the handrails']::text[], null, 1, 1, 'Increase duration first, then incline, then pace, once the current session feels comfortably sustainable.', ARRAY['walking-lunges']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('flat-treadmill-jog', 'Flat Treadmill Jog', ARRAY['full_body']::text[], ARRAY['quads', 'calves', 'hamstrings']::text[], 'cardio', ARRAY['treadmill']::text[], true, false, 'bodyweight', 'Step onto the treadmill on a flat (0-1%) incline and build gradually from a walk to a light jogging pace.', 'Jog at a steady, conversational pace for the prescribed duration, landing softly under the hips rather than overstriding, arms swinging loosely at the sides.', 'Settle into a steady breathing rhythm matched to your stride; slow down if you cannot maintain controlled breathing.', ARRAY['Overstriding and landing heavily on the heel with a locked knee', 'Gripping the front console or side rails while jogging', 'Starting at too fast a pace before warming up with a walk']::text[], 'low', 'none', 'No hand loading — arms swing freely; avoid grabbing the rails while jogging as sudden grabs under momentum can jolt the wrist.', 'Free arm swing with no grip demand makes this safe for the forearm; keep a hand near the emergency stop clip rather than gripping the rails during the jog itself.', '{}', null, 1, 1, 'Increase jogging duration in small increments before increasing pace.', ARRAY['incline-treadmill-walk']::text[], null, true) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('barbell-back-squat', 'Barbell Back Squat', ARRAY['quads']::text[], ARRAY['glutes', 'hamstrings', 'core']::text[], 'squat', ARRAY['barbell']::text[], true, false, 'machine_stack', 'Position the barbell across the upper back/traps in a squat rack, hands gripping the bar wide of the shoulders, feet shoulder-width apart under the bar.', 'Unrack the bar, squat down by bending the knees and hips until thighs are roughly parallel to the floor, then drive back up to standing.', 'Brace and inhale before descending, exhale as you drive back up to standing.', ARRAY['Gripping the bar too tightly with an overextended wrist to keep it stable on the back', 'Rounding the lower back at the bottom of the squat', 'Letting the knees cave inward on the ascent']::text[], 'high', 'pronated', 'A loaded barbell rests on the back and both hands must maintain a fixed, weight-bearing overhand grip to stabilise it for the entire set.', 'Stabilising a loaded bar requires a sustained, forceful overhand wrist extension — this is exactly the kind of heavy barbell grip work to avoid with the titanium-plated right forearm. Use the leg press or goblet squat instead.', ARRAY['Not selectable by default — heavy barbell grip/wrist-extension work is contraindicated for the plated right forearm', 'No barbell equipment currently available at home', 'Avoid entirely until specifically cleared by a physician for loaded barbell grip work']::text[], null, 5, 10, 'Not applicable while contraindicated; use leg press progression instead.', ARRAY['leg-press', 'goblet-squat']::text[], null, false) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('barbell-bench-press', 'Barbell Bench Press', ARRAY['chest']::text[], ARRAY['triceps', 'shoulders']::text[], 'horizontal_push', ARRAY['barbell', 'bench']::text[], true, false, 'machine_stack', 'Lie on a flat bench under a racked barbell, hands gripping the bar just wider than shoulder width, feet flat on the floor.', 'Unrack the bar, lower it under control to the mid-chest, then press it back up to full arm extension.', 'Inhale lowering the bar, exhale pressing it back up.', ARRAY['Gripping the bar unevenly, forcing one wrist to bear more torque than the other', 'Bouncing the bar off the chest', 'Flaring the elbows to 90 degrees under heavy load']::text[], 'high', 'pronated', 'Both hands share a single loaded bar with a fixed overhand grip; any grip imbalance forces extra wrist extension load onto one side, risking the plated forearm.', 'A fixed-bar overhand grip under heavy load is classic heavy barbell grip work — avoid this with the titanium-plated right forearm and use the machine chest press instead.', ARRAY['Not selectable by default — heavy barbell grip/wrist-extension work is contraindicated for the plated right forearm', 'No barbell equipment currently available at home', 'Avoid entirely until specifically cleared by a physician']::text[], null, 5, 10, 'Not applicable while contraindicated; use the machine chest press progression instead.', ARRAY['machine-chest-press', 'flat-dumbbell-press']::text[], null, false) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('barbell-bent-over-row', 'Barbell Bent-Over Row', ARRAY['back']::text[], ARRAY['lats', 'biceps', 'traps']::text[], 'horizontal_pull', ARRAY['barbell']::text[], true, false, 'machine_stack', 'Stand holding a loaded barbell with an overhand grip, hinge forward at the hips until the torso is close to parallel with the floor, back flat.', 'Row the bar up toward the lower ribs by driving the elbows back, then lower under control to a full stretch.', 'Exhale rowing up, inhale lowering back down.', ARRAY['Rounding the lower back under the load', 'Using body momentum/jerking to heave the bar up', 'Overgripping the bar to compensate for an unstable hinge position']::text[], 'high', 'pronated', 'Both hands must maintain a sustained, heavy overhand grip on a single loaded bar while hinged forward — a high, fixed grip demand.', 'The bent-over hinge combined with a heavy fixed overhand bar grip is a classic high-risk pattern for the plated forearm — use the single-arm dumbbell row or seated cable row instead.', ARRAY['Not selectable by default — heavy barbell grip work is contraindicated for the plated right forearm', 'No barbell equipment currently available at home', 'Avoid entirely until specifically cleared by a physician']::text[], null, 6, 10, 'Not applicable while contraindicated; use the seated cable row progression instead.', ARRAY['seated-cable-row', 'single-arm-dumbbell-row']::text[], null, false) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('barbell-deadlift', 'Barbell Deadlift', ARRAY['hamstrings']::text[], ARRAY['glutes', 'back', 'forearms']::text[], 'hinge', ARRAY['barbell']::text[], true, false, 'machine_stack', 'Stand with the loaded bar over mid-foot, hinge down to grip it just outside the shins with a flat back.', 'Drive through the floor to stand up tall, keeping the bar close to the body throughout, then reverse the hinge under control to return the bar to the floor.', 'Brace and inhale before the pull, exhale once the lockout is achieved.', ARRAY['Rounding the lower back to initiate the pull', 'Letting the bar drift away from the shins/legs, adding grip and low-back strain', 'Overgripping the bar under maximal load']::text[], 'high', 'pronated', 'Both hands must sustain a maximal-effort grip on a single heavy bar for the entire lift — the highest wrist/forearm demand exercise in the directory.', 'The deadlift''s maximal sustained grip under the heaviest loads in a training programme is explicitly the type of heavy barbell grip work to avoid with the titanium-plated right forearm — use the dumbbell Romanian deadlift instead.', ARRAY['Not selectable by default — maximal heavy barbell grip work is contraindicated for the plated right forearm', 'No barbell equipment currently available at home', 'Avoid entirely until specifically cleared by a physician for maximal grip loading']::text[], null, 3, 8, 'Not applicable while contraindicated; use the dumbbell Romanian deadlift progression instead.', ARRAY['dumbbell-romanian-deadlift', 'single-leg-dumbbell-rdl']::text[], null, false) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('barbell-overhead-press', 'Barbell Overhead Press', ARRAY['shoulders']::text[], ARRAY['triceps', 'core']::text[], 'vertical_push', ARRAY['barbell']::text[], true, false, 'machine_stack', 'Stand holding a loaded barbell at shoulder height with a pronated grip just outside shoulder width, core braced.', 'Press the bar straight overhead until the arms are extended, then lower under control back to the shoulders.', 'Brace and inhale before pressing, exhale as the bar passes the head.', ARRAY['Overextending the wrist backward to balance the bar overhead', 'Arching the lower back excessively to press the weight up', 'Pressing the bar out in front instead of in a straight vertical line']::text[], 'high', 'pronated', 'Both hands must maintain a fixed, weight-bearing overhand grip on a single loaded bar throughout the overhead lockout.', 'Overhead barbell pressing forces significant wrist extension to keep the bar balanced over the hands — avoid with the titanium-plated right forearm and use the shoulder press machine instead.', ARRAY['Not selectable by default — heavy barbell grip/overhead wrist-extension work is contraindicated for the plated right forearm', 'No barbell equipment currently available at home', 'Avoid entirely until specifically cleared by a physician']::text[], null, 6, 10, 'Not applicable while contraindicated; use the shoulder press machine progression instead.', ARRAY['shoulder-press-machine', 'dumbbell-shoulder-press']::text[], null, false) on conflict (slug) do nothing;
insert into exercises (slug, name, primary_muscles, secondary_muscles, movement_pattern, equipment, is_compound, is_unilateral, load_basis, setup_instructions, execution_instructions, breathing_guidance, common_mistakes, wrist_load_category, recommended_grip, per_hand_or_total_note, safety_note, contraindications, per_hand_weight_limit_kg, suggested_rep_range_low, suggested_rep_range_high, progression_method, substitute_exercise_slugs, video_url, is_selectable_by_default) values ('barbell-bicep-curl', 'Barbell Bicep Curl', ARRAY['biceps']::text[], ARRAY['forearms']::text[], 'isolation_flexion', ARRAY['barbell']::text[], false, false, 'machine_stack', 'Stand holding a loaded barbell with an underhand, shoulder-width grip, arms extended in front of the thighs.', 'Curl the bar up toward the shoulders, keeping elbows pinned to your sides, then lower under control to full extension.', 'Exhale curling up, inhale lowering down.', ARRAY['Swinging the torso/hips to heave the bar up', 'Using a fixed bar width that forces an unnatural wrist angle for one or both hands', 'Not fully extending the arms at the bottom']::text[], 'high', 'supinated', 'The fixed straight bar forces both wrists into an identical, non-adjustable supinated angle, which can concentrate torque on the plated forearm if the wrist''s natural angle differs slightly between sides.', 'A fixed barbell removes the wrist''s ability to find its own natural rotation, unlike independent dumbbells — avoid with the titanium-plated right forearm and use the hammer curl or cable curl instead.', ARRAY['Not selectable by default — fixed-bar grip work is contraindicated for the plated right forearm', 'No barbell equipment currently available at home', 'Avoid entirely until specifically cleared by a physician']::text[], null, 8, 12, 'Not applicable while contraindicated; use the hammer curl or cable curl progression instead.', ARRAY['hammer-curl', 'cable-curl']::text[], null, false) on conflict (slug) do nothing;
