insert into exercise_substitutions (exercise_slug, substitute_slug, reason) values ('cable-hammer-curl', 'hammer-curl', 'Home-available dumbbell alternative with the same forearm-friendly neutral grip.');
insert into exercise_substitutions (exercise_slug, substitute_slug, reason) values ('incline-dumbbell-curl', 'hammer-curl', 'Reduces wrist leverage by using a neutral grip instead of a deep-stretch supinated curl.');
insert into exercise_substitutions (exercise_slug, substitute_slug, reason) values ('single-arm-triceps-pushdown', 'triceps-rope-pushdown', 'Bilateral rope version for days unilateral stabilisation is not needed.');
insert into exercise_substitutions (exercise_slug, substitute_slug, reason) values ('leg-press-single-leg', 'leg-press', 'Bilateral version when unilateral balance/control is not the current training focus.');
insert into exercise_substitutions (exercise_slug, substitute_slug, reason) values ('cable-pull-through', 'dumbbell-romanian-deadlift', 'Home-available dumbbell hinge alternative when cable stack access is limited.');
insert into exercise_substitutions (exercise_slug, substitute_slug, reason) values ('single-leg-glute-bridge', 'glute-bridge', 'Bilateral bodyweight version with zero forearm loading, easier to control.');
insert into exercise_substitutions (exercise_slug, substitute_slug, reason) values ('side-plank', 'cable-crunch', 'Removes sustained forearm weight-bearing on the plated right side entirely.');
