-- ============================================================
-- Nithish Fit: full Supabase setup (schema + RLS + reference data)
-- Paste this entire file into the Supabase SQL editor and run it once.
-- ============================================================

-- ---- 0001_extensions.sql ----
-- Nithish Fit: extensions and shared helpers
create extension if not exists "pgcrypto";

-- Generic updated_at trigger used by most tables.
create or replace function set_updated_at()
returns trigger as $$
begin
  new.updated_at = now();
  return new;
end;
$$ language plpgsql;

-- ---- 0002_profile.sql ----
-- User profile, preferences and medical restrictions.
-- Single-user app: user_id references auth.users(id); RLS (0011) scopes every row to auth.uid().

create table user_profiles (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade unique,
  name text not null,
  sex text not null check (sex in ('male', 'female')),
  age integer not null check (age between 10 and 100),
  height_cm numeric(5,1) not null check (height_cm between 50 and 250),
  current_weight_kg numeric(5,2) not null check (current_weight_kg between 30 and 300),
  target_weight_kg numeric(5,2) not null check (target_weight_kg between 30 and 300),
  primary_goal text not null check (primary_goal in ('fat_loss', 'muscle_gain', 'maintenance', 'recomposition')),
  training_experience text not null check (training_experience in ('beginner', 'intermediate', 'advanced')),
  country text not null default 'India',
  dietary_pattern text not null check (dietary_pattern in ('indian_vegetarian', 'indian_non_vegetarian', 'indian_eggetarian', 'other')),
  training_days text[] not null default '{}',
  rest_days text[] not null default '{}',
  gym_type text not null,
  preferred_workout_duration_min_minutes integer not null,
  preferred_workout_duration_max_minutes integer not null,
  creatine_grams_per_day numeric(4,1) not null default 0,
  whey_scoops_per_training_day numeric(3,1) not null default 0,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
create trigger trg_user_profiles_updated_at before update on user_profiles
  for each row execute function set_updated_at();

create table user_preferences (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade unique,
  units text not null default 'metric',
  theme text not null default 'system' check (theme in ('light', 'dark', 'system')),
  activity_level text not null check (activity_level in ('sedentary', 'lightly_active', 'moderately_active', 'very_active', 'custom')),
  custom_activity_multiplier numeric(3,2),
  calorie_deficit_percent numeric(4,1) not null default 17.5,
  protein_grams_per_kg numeric(3,2) not null default 1.9,
  fat_grams_per_kg_target numeric(3,2) not null default 0.8,
  fibre_target_grams_min integer not null default 30,
  fibre_target_grams_max integer not null default 40,
  water_target_ml integer not null default 3000,
  updated_at timestamptz not null default now()
);
create trigger trg_user_preferences_updated_at before update on user_preferences
  for each row execute function set_updated_at();

create table medical_restrictions (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade,
  label text not null,
  description text not null,
  body_part text not null,
  max_load_per_hand_kg numeric(5,2),
  active boolean not null default true,
  since date not null,
  notes text,
  created_at timestamptz not null default now()
);
create index idx_medical_restrictions_user on medical_restrictions(user_id) where active;

create table application_settings (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade,
  key text not null,
  value text not null,
  updated_at timestamptz not null default now(),
  unique (user_id, key)
);
create trigger trg_application_settings_updated_at before update on application_settings
  for each row execute function set_updated_at();

-- ---- 0003_equipment.sql ----
-- Equipment catalogue (global reference data) + per-user enable/disable + weight increments.

create table equipment (
  id uuid primary key default gen_random_uuid(),
  type text not null unique,
  name text not null,
  notes text
);

create table user_equipment (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade,
  equipment_id uuid not null references equipment(id) on delete cascade,
  enabled boolean not null default true,
  max_load_kg numeric(6,2),
  updated_at timestamptz not null default now(),
  unique (user_id, equipment_id)
);
create trigger trg_user_equipment_updated_at before update on user_equipment
  for each row execute function set_updated_at();
create index idx_user_equipment_user on user_equipment(user_id);

create table available_weight_increments (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade,
  equipment_type text not null,
  increment_kg numeric(4,2) not null,
  min_kg numeric(5,2) not null default 0,
  max_kg numeric(5,2) not null,
  unique (user_id, equipment_type)
);

-- ---- 0004_exercises.sql ----
-- Exercise directory (global reference data, seeded once; readable by all authenticated users).

create table exercises (
  id uuid primary key default gen_random_uuid(),
  slug text not null unique,
  name text not null,
  primary_muscles text[] not null,
  secondary_muscles text[] not null default '{}',
  movement_pattern text not null,
  equipment text[] not null,
  is_compound boolean not null,
  is_unilateral boolean not null,
  load_basis text not null check (load_basis in ('per_hand', 'total', 'machine_stack', 'bodyweight')),
  setup_instructions text not null,
  execution_instructions text not null,
  breathing_guidance text not null,
  common_mistakes text[] not null default '{}',
  wrist_load_category text not null check (wrist_load_category in ('low', 'moderate', 'high')),
  recommended_grip text not null,
  per_hand_or_total_note text not null,
  safety_note text not null,
  contraindications text[] not null default '{}',
  per_hand_weight_limit_kg numeric(5,2),
  suggested_rep_range_low integer not null,
  suggested_rep_range_high integer not null,
  progression_method text not null,
  substitute_exercise_slugs text[] not null default '{}',
  video_url text,
  is_selectable_by_default boolean not null default true,
  deleted_at timestamptz,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
create trigger trg_exercises_updated_at before update on exercises
  for each row execute function set_updated_at();
create index idx_exercises_primary_muscles on exercises using gin (primary_muscles);
create index idx_exercises_equipment on exercises using gin (equipment);
create index idx_exercises_movement_pattern on exercises(movement_pattern);

create table exercise_aliases (
  id uuid primary key default gen_random_uuid(),
  exercise_slug text not null references exercises(slug) on delete cascade,
  alias text not null
);
create index idx_exercise_aliases_slug on exercise_aliases(exercise_slug);
create index idx_exercise_aliases_alias on exercise_aliases(lower(alias));

create table exercise_substitutions (
  id uuid primary key default gen_random_uuid(),
  exercise_slug text not null references exercises(slug) on delete cascade,
  substitute_slug text not null references exercises(slug) on delete cascade,
  reason text not null
);
create index idx_exercise_substitutions_slug on exercise_substitutions(exercise_slug);

-- ---- 0005_programme.sql ----
-- Workout programme structure: programme -> days -> planned exercises.

create table workout_programmes (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade,
  name text not null,
  description text,
  is_active boolean not null default false,
  started_on date not null,
  cycle_weeks integer not null default 5,
  deleted_at timestamptz,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
create trigger trg_workout_programmes_updated_at before update on workout_programmes
  for each row execute function set_updated_at();
create index idx_workout_programmes_user on workout_programmes(user_id) where deleted_at is null;

create table workout_days (
  id uuid primary key default gen_random_uuid(),
  programme_id uuid not null references workout_programmes(id) on delete cascade,
  label text not null,
  weekday text check (weekday in ('monday','tuesday','wednesday','thursday','friday','saturday','sunday')),
  is_rest_day boolean not null default false,
  order_index integer not null default 0
);
create index idx_workout_days_programme on workout_days(programme_id);

create table planned_exercises (
  id uuid primary key default gen_random_uuid(),
  workout_day_id uuid not null references workout_days(id) on delete cascade,
  exercise_slug text not null references exercises(slug),
  order_index integer not null default 0,
  target_sets integer not null,
  target_reps_low integer not null,
  target_reps_high integer not null,
  rest_seconds integer not null default 90,
  notes text
);
create index idx_planned_exercises_day on planned_exercises(workout_day_id);

-- ---- 0006_sessions.sql ----
-- Actual training sessions: readiness -> session -> per-exercise performance -> sets.

create table readiness_entries (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade,
  date date not null,
  sleep_hours numeric(3,1) not null,
  energy_level integer not null check (energy_level between 1 and 5),
  muscle_soreness integer not null check (muscle_soreness between 1 and 5),
  wrist_pain integer not null check (wrist_pain between 0 and 10),
  stress_level integer not null check (stress_level between 1 and 5),
  created_at timestamptz not null default now()
);
create index idx_readiness_entries_user_date on readiness_entries(user_id, date desc);

create table workout_sessions (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade,
  programme_id uuid references workout_programmes(id) on delete set null,
  workout_day_id uuid references workout_days(id) on delete set null,
  label text not null,
  date date not null,
  started_at timestamptz,
  completed_at timestamptz,
  status text not null default 'planned' check (status in ('planned', 'in_progress', 'completed', 'skipped')),
  readiness_entry_id uuid references readiness_entries(id) on delete set null,
  session_difficulty integer check (session_difficulty between 1 and 10),
  wrist_pain_score integer check (wrist_pain_score between 0 and 10),
  notes text,
  is_deload boolean not null default false,
  duration_minutes numeric(5,1),
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
create trigger trg_workout_sessions_updated_at before update on workout_sessions
  for each row execute function set_updated_at();
create index idx_workout_sessions_user_date on workout_sessions(user_id, date desc);

create table exercise_performances (
  id uuid primary key default gen_random_uuid(),
  session_id uuid not null references workout_sessions(id) on delete cascade,
  exercise_slug text not null references exercises(slug),
  order_index integer not null default 0,
  was_skipped boolean not null default false,
  was_replaced_by_slug text references exercises(slug),
  was_added_extra boolean not null default false,
  note text
);
create index idx_exercise_performances_session on exercise_performances(session_id);
create index idx_exercise_performances_slug on exercise_performances(exercise_slug);

create table exercise_sets (
  id uuid primary key default gen_random_uuid(),
  performance_id uuid not null references exercise_performances(id) on delete cascade,
  set_number integer not null,
  suggested_weight_kg numeric(5,2),
  actual_weight_kg numeric(5,2),
  suggested_reps integer,
  actual_reps integer,
  rir numeric(3,1),
  pain_score integer check (pain_score between 0 and 10),
  completed boolean not null default false,
  timestamp timestamptz not null default now(),
  note text
);
create index idx_exercise_sets_performance on exercise_sets(performance_id);

-- ---- 0007_body_and_nutrition_targets.sql ----
-- Body measurements and nutrition targets.

create table body_measurements (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade,
  date date not null,
  weight_kg numeric(5,2) not null,
  waist_cm numeric(5,2),
  note text,
  photo_meta jsonb,
  created_at timestamptz not null default now(),
  unique (user_id, date)
);
create index idx_body_measurements_user_date on body_measurements(user_id, date desc);

create table nutrition_targets (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade,
  effective_from date not null,
  bmr_kcal numeric(6,1) not null,
  activity_level text not null,
  activity_multiplier numeric(3,2) not null,
  maintenance_kcal numeric(6,1) not null,
  deficit_percent numeric(4,1) not null,
  calorie_target_kcal numeric(6,1) not null,
  protein_target_g numeric(5,1) not null,
  fat_target_g numeric(5,1) not null,
  carb_target_g numeric(5,1) not null,
  fibre_target_g numeric(5,1) not null,
  is_active boolean not null default false,
  is_user_override boolean not null default false,
  created_at timestamptz not null default now()
);
create index idx_nutrition_targets_user_active on nutrition_targets(user_id) where is_active;

-- ---- 0008_food.sql ----
-- Indian food database: items, servings, aliases, recipes, and the food log.

create table food_items (
  id uuid primary key default gen_random_uuid(),
  slug text not null unique,
  name text not null,
  category text not null,
  cuisine_tag text,
  raw_cooked_state text not null check (raw_cooked_state in ('raw', 'cooked', 'not_applicable')),
  preparation_method text,
  calories_per_100g numeric(6,2) not null,
  protein_per_100g numeric(5,2) not null,
  carbs_per_100g numeric(5,2) not null,
  fat_per_100g numeric(5,2) not null,
  fibre_per_100g numeric(5,2) not null,
  source text not null,
  measurement_basis text not null,
  reliability text not null check (reliability in ('verified', 'estimated', 'user_provided')),
  last_updated date not null,
  is_custom boolean not null default false,
  owner_user_id uuid references auth.users(id) on delete cascade,
  deleted_at timestamptz,
  created_at timestamptz not null default now()
);
create index idx_food_items_category on food_items(category);
create index idx_food_items_owner on food_items(owner_user_id);
create index idx_food_items_name_trgm on food_items using gin (to_tsvector('simple', name));

create table food_servings (
  id uuid primary key default gen_random_uuid(),
  food_item_id uuid not null references food_items(id) on delete cascade,
  unit text not null,
  grams_equivalent numeric(7,2) not null,
  label text not null,
  is_default boolean not null default false
);
create index idx_food_servings_item on food_servings(food_item_id);

create table food_aliases (
  id uuid primary key default gen_random_uuid(),
  food_item_id uuid not null references food_items(id) on delete cascade,
  alias text not null,
  is_user_correction boolean not null default false,
  owner_user_id uuid references auth.users(id) on delete cascade
);
create index idx_food_aliases_item on food_aliases(food_item_id);
create index idx_food_aliases_alias on food_aliases(lower(alias));

create table recipes (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade,
  name text not null,
  cuisine_tag text,
  total_cooked_weight_grams numeric(7,2) not null,
  servings numeric(4,1) not null,
  cooking_oil_grams numeric(6,2) not null default 0,
  instructions text,
  deleted_at timestamptz,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
create trigger trg_recipes_updated_at before update on recipes
  for each row execute function set_updated_at();
create index idx_recipes_user on recipes(user_id) where deleted_at is null;

create table recipe_ingredients (
  id uuid primary key default gen_random_uuid(),
  recipe_id uuid not null references recipes(id) on delete cascade,
  food_item_id uuid not null references food_items(id),
  quantity_grams numeric(7,2) not null,
  note text
);
create index idx_recipe_ingredients_recipe on recipe_ingredients(recipe_id);

create table food_logs (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade,
  date date not null,
  logged_at timestamptz not null default now(),
  raw_text text not null,
  food_item_id uuid references food_items(id),
  recipe_id uuid references recipes(id),
  custom_name text,
  quantity_grams numeric(7,2) not null,
  unit text not null,
  unit_quantity numeric(6,2) not null,
  meal_slot text not null check (meal_slot in ('early_morning','breakfast','mid_morning','lunch','pre_workout','post_workout','dinner','before_bed','unspecified')),
  calories numeric(6,1) not null,
  protein_g numeric(5,1) not null,
  carbs_g numeric(5,1) not null,
  fat_g numeric(5,1) not null,
  fibre_g numeric(5,1) not null,
  confidence text not null check (confidence in ('high', 'medium', 'low')),
  source text not null,
  was_edited boolean not null default false,
  deleted_at timestamptz,
  created_at timestamptz not null default now()
);
create index idx_food_logs_user_date on food_logs(user_id, date desc);

-- ---- 0009_mealplan.sql ----
-- Meal plans: plan -> days -> planned meals (items stored as jsonb since they're a
-- small denormalised list of {foodItemId|recipeId, name, quantityGrams, displayQuantity}).

create table meal_plans (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade,
  name text not null,
  start_date date not null,
  preferences jsonb not null,
  target_calories numeric(6,1) not null,
  target_protein_g numeric(5,1) not null,
  target_fat_g numeric(5,1) not null,
  target_fibre_g numeric(5,1) not null,
  deleted_at timestamptz,
  created_at timestamptz not null default now()
);
create index idx_meal_plans_user on meal_plans(user_id) where deleted_at is null;

create table meal_plan_days (
  id uuid primary key default gen_random_uuid(),
  meal_plan_id uuid not null references meal_plans(id) on delete cascade,
  day_index integer not null check (day_index between 0 and 6),
  date date,
  is_vegetarian_day boolean not null default false
);
create index idx_meal_plan_days_plan on meal_plan_days(meal_plan_id);

create table planned_meals (
  id uuid primary key default gen_random_uuid(),
  meal_plan_day_id uuid not null references meal_plan_days(id) on delete cascade,
  slot text not null check (slot in ('early_morning','breakfast','mid_morning','lunch','pre_workout','post_workout','dinner','before_bed')),
  title text not null,
  items jsonb not null,
  calories numeric(6,1) not null,
  protein_g numeric(5,1) not null,
  carbs_g numeric(5,1) not null,
  fat_g numeric(5,1) not null,
  fibre_g numeric(5,1) not null,
  preparation_guidance text not null,
  swap_options text[] not null default '{}'
);
create index idx_planned_meals_day on planned_meals(meal_plan_day_id);

-- ---- 0010_supplements.sql ----
create table supplement_logs (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade,
  date date not null,
  type text not null check (type in ('creatine', 'whey')),
  amount text not null,
  taken boolean not null default false,
  taken_at timestamptz,
  unique (user_id, date, type)
);
create index idx_supplement_logs_user_date on supplement_logs(user_id, date desc);

-- ---- 0011_rls.sql ----
-- Row-level security. This is a single-user app, but RLS is still enforced properly:
-- every user-owned table is scoped to auth.uid(), and global reference tables
-- (exercises, equipment, non-custom food items) are read-only to authenticated users.

-- ---- User-owned tables: full CRUD scoped to auth.uid() = user_id ----
alter table user_profiles enable row level security;
alter table user_preferences enable row level security;
alter table medical_restrictions enable row level security;
alter table application_settings enable row level security;
alter table user_equipment enable row level security;
alter table available_weight_increments enable row level security;
alter table workout_programmes enable row level security;
alter table workout_sessions enable row level security;
alter table readiness_entries enable row level security;
alter table body_measurements enable row level security;
alter table nutrition_targets enable row level security;
alter table recipes enable row level security;
alter table food_logs enable row level security;
alter table meal_plans enable row level security;
alter table supplement_logs enable row level security;

do $$
declare
  t text;
begin
  foreach t in array array[
    'user_profiles', 'user_preferences', 'medical_restrictions', 'application_settings',
    'user_equipment', 'available_weight_increments', 'workout_programmes', 'workout_sessions',
    'readiness_entries', 'body_measurements', 'nutrition_targets', 'recipes', 'food_logs',
    'meal_plans', 'supplement_logs'
  ]
  loop
    execute format('create policy %I_select_own on %I for select using (auth.uid() = user_id)', t, t);
    execute format('create policy %I_insert_own on %I for insert with check (auth.uid() = user_id)', t, t);
    execute format('create policy %I_update_own on %I for update using (auth.uid() = user_id) with check (auth.uid() = user_id)', t, t);
    execute format('create policy %I_delete_own on %I for delete using (auth.uid() = user_id)', t, t);
  end loop;
end $$;

-- ---- Child tables: scoped via their parent's user_id ----
alter table workout_days enable row level security;
create policy workout_days_all_own on workout_days for all
  using (exists (select 1 from workout_programmes p where p.id = workout_days.programme_id and p.user_id = auth.uid()))
  with check (exists (select 1 from workout_programmes p where p.id = workout_days.programme_id and p.user_id = auth.uid()));

alter table planned_exercises enable row level security;
create policy planned_exercises_all_own on planned_exercises for all
  using (exists (select 1 from workout_days d join workout_programmes p on p.id = d.programme_id where d.id = planned_exercises.workout_day_id and p.user_id = auth.uid()))
  with check (exists (select 1 from workout_days d join workout_programmes p on p.id = d.programme_id where d.id = planned_exercises.workout_day_id and p.user_id = auth.uid()));

alter table exercise_performances enable row level security;
create policy exercise_performances_all_own on exercise_performances for all
  using (exists (select 1 from workout_sessions s where s.id = exercise_performances.session_id and s.user_id = auth.uid()))
  with check (exists (select 1 from workout_sessions s where s.id = exercise_performances.session_id and s.user_id = auth.uid()));

alter table exercise_sets enable row level security;
create policy exercise_sets_all_own on exercise_sets for all
  using (exists (select 1 from exercise_performances ep join workout_sessions s on s.id = ep.session_id where ep.id = exercise_sets.performance_id and s.user_id = auth.uid()))
  with check (exists (select 1 from exercise_performances ep join workout_sessions s on s.id = ep.session_id where ep.id = exercise_sets.performance_id and s.user_id = auth.uid()));

alter table recipe_ingredients enable row level security;
create policy recipe_ingredients_all_own on recipe_ingredients for all
  using (exists (select 1 from recipes r where r.id = recipe_ingredients.recipe_id and r.user_id = auth.uid()))
  with check (exists (select 1 from recipes r where r.id = recipe_ingredients.recipe_id and r.user_id = auth.uid()));

alter table meal_plan_days enable row level security;
create policy meal_plan_days_all_own on meal_plan_days for all
  using (exists (select 1 from meal_plans mp where mp.id = meal_plan_days.meal_plan_id and mp.user_id = auth.uid()))
  with check (exists (select 1 from meal_plans mp where mp.id = meal_plan_days.meal_plan_id and mp.user_id = auth.uid()));

alter table planned_meals enable row level security;
create policy planned_meals_all_own on planned_meals for all
  using (exists (select 1 from meal_plan_days d join meal_plans mp on mp.id = d.meal_plan_id where d.id = planned_meals.meal_plan_day_id and mp.user_id = auth.uid()))
  with check (exists (select 1 from meal_plan_days d join meal_plans mp on mp.id = d.meal_plan_id where d.id = planned_meals.meal_plan_day_id and mp.user_id = auth.uid()));

-- ---- Global reference data: readable by any authenticated user, not writable by clients ----
alter table equipment enable row level security;
create policy equipment_read_all on equipment for select using (auth.role() = 'authenticated');

alter table exercises enable row level security;
create policy exercises_read_all on exercises for select using (auth.role() = 'authenticated');

alter table exercise_aliases enable row level security;
create policy exercise_aliases_read_all on exercise_aliases for select using (auth.role() = 'authenticated');

alter table exercise_substitutions enable row level security;
create policy exercise_substitutions_read_all on exercise_substitutions for select using (auth.role() = 'authenticated');

-- food_items: global entries readable by everyone; custom entries scoped to their owner.
alter table food_items enable row level security;
create policy food_items_read on food_items for select
  using (is_custom = false or owner_user_id = auth.uid());
create policy food_items_insert_own_custom on food_items for insert
  with check (is_custom = true and owner_user_id = auth.uid());
create policy food_items_update_own_custom on food_items for update
  using (is_custom = true and owner_user_id = auth.uid())
  with check (is_custom = true and owner_user_id = auth.uid());
create policy food_items_delete_own_custom on food_items for delete
  using (is_custom = true and owner_user_id = auth.uid());

alter table food_servings enable row level security;
create policy food_servings_read on food_servings for select
  using (exists (select 1 from food_items f where f.id = food_servings.food_item_id and (f.is_custom = false or f.owner_user_id = auth.uid())));
create policy food_servings_write_own on food_servings for insert
  with check (exists (select 1 from food_items f where f.id = food_servings.food_item_id and f.is_custom = true and f.owner_user_id = auth.uid()));

alter table food_aliases enable row level security;
create policy food_aliases_read on food_aliases for select
  using (owner_user_id is null or owner_user_id = auth.uid());
create policy food_aliases_insert_own on food_aliases for insert
  with check (owner_user_id = auth.uid());

